import { GoogleGenAI, Type } from "@google/genai";
import { SportCategory, DifficultyLevel } from "../types";
import * as storage from "./storage";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export interface AIGameSuggestion {
  title: string;
  description: string;
  category: SportCategory;
  difficulty: DifficultyLevel;
  durationMin: number;
}

export const generateGameIdea = async (
  prompt: string, 
  language: 'en' | 'es' = 'en',
): Promise<AIGameSuggestion> => {

  const sportConfig = storage.getSportConfig();
  const langPrompt = language === 'es' ? 'Salida puramente en Español.' : 'Output purely in English.';
  const finalPrompt = `Crea un ejercicio o juego de entrenamiento para ${sportConfig.name} enfocado en: ${prompt}. Asegúrate de que las reglas sean claras y acordes al deporte ${sportConfig.name}. ${langPrompt}`;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: finalPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING, description: "Nombre atractivo del juego" },
            description: { type: Type.STRING, description: "Reglas detalladas y configuración" },
            category: { 
              type: Type.STRING, 
              enum: [
                SportCategory.WARMUP,
                SportCategory.TECHNICAL,
                SportCategory.TACTICAL,
                SportCategory.PHYSICAL,
                SportCategory.GENERAL
              ] 
            },
            difficulty: {
              type: Type.STRING,
              enum: [
                DifficultyLevel.U5,
                DifficultyLevel.U7,
                DifficultyLevel.U9,
                DifficultyLevel.U12,
                DifficultyLevel.U16,
                DifficultyLevel.SENIOR,
                DifficultyLevel.ALL_AGES
              ]
            },
            durationMin: { type: Type.INTEGER, description: "Duración recomendada en minutos" }
          },
          required: ["title", "description", "category", "difficulty", "durationMin"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No response from AI");

    return JSON.parse(text) as AIGameSuggestion;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

