const LanguageContext = createContext<LanguageContextType | undefined>(undefined);

export const LanguageProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<Language>('es');
  const t = (key: string): string => translations[key]?.[language] || key;
  return (
    <LanguageContext.Provider value={{ language, setLanguage, t }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) throw new Error('useLanguage error');
  return context;
};

import React, { useState, useEffect } from 'react';
import { Plus, Users, ClipboardCheck, Trash2, CheckCircle, Eye, X, FolderPlus, Layers } from 'lucide-react';
import { Student, AttendanceRecord, Group, DifficultyLevel } from '../types';
import * as storage from '../services/storage';
import { useLanguage } from '../LanguageContext';

const StudentsView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'GROUPS' | 'REGISTER' | 'LIST' | 'ATTENDANCE'>('GROUPS');
  const [students, setStudents] = useState<Student[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const { t } = useLanguage();

  // Selection
  const [selectedGroupId, setSelectedGroupId] = useState<string>('');

  // Form Student
  const [studentForm, setStudentForm] = useState<Partial<Student>>({
    firstName: '', lastName: '', age: 0, position: '', groupId: '', emergencyContact: ''
  });

  // Form Group
  const [groupForm, setGroupForm] = useState<Partial<Group>>({
    name: '', description: '', level: DifficultyLevel.ALL_AGES
  });

  // Attendance
  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [presentIds, setPresentIds] = useState<Set<string>>(new Set());
  const [attendanceSaved, setAttendanceSaved] = useState(false);

  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setLoading(true);
    const [s, g, a] = await Promise.all([
      storage.getStudents(),
      storage.getGroups(),
      storage.getAttendance()
    ]);
    setStudents(s);
    setGroups(g);
    setAttendanceRecords(a);
    if (g.length > 0 && !selectedGroupId) setSelectedGroupId(g[0].id);
    setLoading(false);
