        <button onClick={() => setActiveTab('REGISTER')} className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition ${activeTab === 'REGISTER' ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white text-slate-600 hover:bg-slate-100'}`}>
