              <select className="p-2 border rounded-lg bg-slate-50 font-bold text-indigo-600" value={selectedGroupId} onChange={e => setSelectedGroupId(e.target.value)}>
                {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
              </select>
            </div>
            <div className="overflow-x-auto">
              <table className="w-full text-left">
