            </div>

            <div className="flex justify-end border-t border-slate-50 pt-6">
              <button onClick={saveAttendance} disabled={attendanceSaved || filteredStudents.length === 0} className={`px-10 py-4 rounded-2xl font-black text-white transition shadow-xl ${attendanceSaved ? 'bg-green-600' : 'bg-slate-900 hover:bg-slate-800 disabled:opacity-30'}`}>
                {attendanceSaved ? '¡LISTA GUARDADA!' : 'GUARDAR ASISTENCIA'}
              </button>
            </div>
          </div>
        )}

      </div>
    </div>
  );
};

