  });

  const [groupForm, setGroupForm] = useState<Partial<Group>>({
    name: '', description: '', level: DifficultyLevel.ALL_AGES
  });

  // Attendance taking state
  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [presentIds, setPresentIds] = useState<Set<string>>(new Set());
  const [attNotes, setAttNotes] = useState('');
  const [attendanceSaved, setAttendanceSaved] = useState(false);

  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setLoading(true);
    const [s, g, a] = await Promise.all([
      storage.getStudents(),
      storage.getGroups(),
      storage.getAttendance()
    ]);
    setStudents(s);
    setGroups(g);
    setAttendanceRecords(a);
    if (g.length > 0 && !selectedGroupId) setSelectedGroupId(g[0].id);
    setLoading(false);
  };

  const handleCreateGroup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupForm.name) return;
    const newGroup: Group = {
      id: crypto.randomUUID(),
      name: groupForm.name,
      description: groupForm.description,
      level: groupForm.level,
      createdAt: new Date().toISOString()
    };
    await storage.addGroup(newGroup);
    setGroupForm({ name: '', description: '', level: DifficultyLevel.ALL_AGES });
    setShowGroupModal(false);
    loadAllData();
  };

  const handleRegisterStudent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studentForm.firstName || !studentForm.groupId) return;
    const newStudent: Student = {
      ...studentForm as Student,
      id: crypto.randomUUID(),
      active: true
    };
    await storage.addStudent(newStudent);
    setShowStudentModal(false);
    loadAllData();
  };

  const saveAttendance = async () => {
    if (!selectedGroupId) return;
    const record: AttendanceRecord = {
      id: crypto.randomUUID(),
      date: attendanceDate,
      groupId: selectedGroupId,
      presentStudentIds: Array.from(presentIds),
      sessionNotes: attNotes
    };
    await storage.saveAttendance(record);
    setAttendanceSaved(true);
    setAttNotes('');
    loadAllData();
    setTimeout(() => setAttendanceSaved(false), 3000);
  };

  const getAttendanceStats = (studentId: string) => {
    const records = attendanceRecords.filter(r => 
      students.find(s => s.id === studentId)?.groupId === r.groupId
    );
    if (records.length === 0) return 0;
    const attended = records.filter(r => r.presentStudentIds.includes(studentId)).length;
    return Math.round((attended / records.length) * 100);
  };

  const filteredGroups = groups.filter(g => g.name.toLowerCase().includes(searchTerm.toLowerCase()));
  const filteredStudents = students.filter(s => 
    s.groupId === selectedGroupId && 
    (s.firstName.toLowerCase().includes(searchTerm.toLowerCase()) || s.lastName.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  const currentGroup = groups.find(g => g.id === selectedGroupId);

  if (loading) return (
    <div className="flex flex-col items-center justify-center h-64 space-y-4">
      <div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-slate-500 font-bold">Cargando gestión deportiva...</p>
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Tab Navigation - Assistance Management Style */}
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200 sticky top-0 z-10 overflow-x-auto">
        <button onClick={() => setActiveTab('GROUPS')} className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-bold transition ${activeTab === 'GROUPS' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
          <Layers size={18} /> {t('groups.title')}
        </button>
        <button onClick={() => setActiveTab('LIST')} className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-bold transition ${activeTab === 'LIST' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
          <Users size={18} /> Alumnos
        </button>
        <button onClick={() => setActiveTab('ATTENDANCE')} className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-bold transition ${activeTab === 'ATTENDANCE' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
          <ClipboardCheck size={18} /> {t('students.attendance')}
        </button>
        <button onClick={() => setActiveTab('HISTORY')} className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-bold transition ${activeTab === 'HISTORY' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}>
          <History size={18} /> Historial
        </button>
      </div>

      {/* Main Content Areas */}
      <div className="min-h-[600px]">

        {/* TAB: GROUPS (Dashboard of all groups) */}
        {activeTab === 'GROUPS' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <div>
                <h2 className="text-2xl font-black text-slate-800">Tus Grupos</h2>
                <p className="text-slate-500 text-sm">Gestiona categorías y horarios</p>
              </div>
              <button 
                onClick={() => setShowGroupModal(true)}
                className="bg-indigo-600 text-white px-5 py-3 rounded-2xl font-bold flex items-center gap-2 hover:bg-indigo-700 transition shadow-lg shadow-indigo-100"
              >
                <FolderPlus size={20} /> Nuevo Grupo
              </button>
            </div>

            <div className="relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
              <input 
                type="text" 
                placeholder="Buscar grupo..." 
                className="w-full pl-12 pr-4 py-4 bg-white border border-slate-200 rounded-2xl focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm"
                value={searchTerm}
                onChange={e => setSearchTerm(e.target.value)}
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredGroups.map(g => {
                const groupStudents = students.filter(s => s.groupId === g.id);
                return (
                  <div key={g.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:border-indigo-100 transition group cursor-pointer" onClick={() => { setSelectedGroupId(g.id); setActiveTab('LIST'); }}>
                    <div className="flex justify-between items-start mb-4">
                      <div className="p-3 bg-slate-50 rounded-2xl group-hover:bg-indigo-50 transition">
                        <Users className="text-indigo-600" />
                      </div>
                      <span className="text-[10px] font-black uppercase tracking-widest bg-slate-100 px-2 py-1 rounded text-slate-500">
                        {t(`diff.${g.level}`)}
                      </span>
                    </div>
                    <h3 className="text-xl font-black text-slate-800 mb-1">{g.name}</h3>
                    <p className="text-slate-400 text-sm line-clamp-1 mb-6">{g.description || 'Sin descripción'}</p>

                    <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                      <div className="flex flex-col">
                        <span className="text-2xl font-black text-slate-900">{groupStudents.length}</span>
                        <span className="text-[10px] font-bold text-slate-400 uppercase">Alumnos</span>
                      </div>
                      <ChevronRight className="text-slate-300 group-hover:text-indigo-600 transition" />
                    </div>
                  </div>
                );
              })}
              {filteredGroups.length === 0 && (
                <div className="col-span-full py-20 bg-white rounded-[2rem] border border-dashed border-slate-200 flex flex-col items-center justify-center text-slate-400">
                  <Layers size={48} className="mb-4 opacity-20" />
                  <p className="font-bold">No hay grupos que coincidan.</p>
                </div>
              )}
            </div>
          </div>
        )}

        {/* TAB: LIST (Students of selected group) */}
        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div className="flex items-center gap-3">
                <div className="p-3 bg-indigo-600 text-white rounded-2xl shadow-lg">
                  <Users size={24} />
                </div>
                <div>
                  <h2 className="text-2xl font-black text-slate-800">{currentGroup?.name || 'Selecciona un grupo'}</h2>
                  <p className="text-slate-400 text-sm">{filteredStudents.length} alumnos registrados</p>
                </div>
              </div>
              <div className="flex gap-2 w-full md:w-auto">
                <select 
                  className="flex-1 md:flex-none p-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-700 outline-none"
                  value={selectedGroupId}
                  onChange={e => setSelectedGroupId(e.target.value)}
                >
                  {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
                <button 
                  onClick={() => setShowStudentModal(true)}
                  className="bg-slate-900 text-white px-4 py-3 rounded-xl font-bold flex items-center gap-2 hover:bg-slate-800 transition"
                >
                  <UserPlus size={18} /> Nuevo
                </button>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead className="bg-slate-50 border-b border-slate-100 text-slate-400 text-[10px] font-black uppercase tracking-[0.2em]">
                    <tr>
                      <th className="px-6 py-4">Alumno</th>
                      <th className="px-6 py-4">Posición</th>
                      <th className="px-6 py-4">Asistencia (%)</th>
                      <th className="px-6 py-4">Contacto</th>
                      <th className="px-6 py-4 text-right">Acciones</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredStudents.map(s => (
                      <tr key={s.id} className="hover:bg-slate-50/50 transition group">
                        <td className="px-6 py-5">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 rounded-full bg-indigo-50 text-indigo-600 flex items-center justify-center font-black text-sm uppercase">
                              {s.firstName[0]}{s.lastName[0]}
                            </div>
                            <div>
                              <div className="font-bold text-slate-800">{s.firstName} {s.lastName}</div>
                              <div className="text-xs text-slate-400">{s.age} años</div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 py-5">
                          <span className="px-3 py-1 bg-blue-50 text-blue-600 text-[10px] font-black rounded-lg uppercase border border-blue-100">
                            {s.position || 'N/A'}
                          </span>
                        </td>
                        <td className="px-6 py-5">
                          <div className="flex items-center gap-2">
                            <div className="flex-1 h-2 bg-slate-100 rounded-full max-w-[100px] overflow-hidden">
                              <div 
                                className={`h-full rounded-full transition-all duration-1000 ${getAttendanceStats(s.id) > 75 ? 'bg-emerald-500' : getAttendanceStats(s.id) > 40 ? 'bg-amber-500' : 'bg-rose-500'}`}
                                style={{ width: `${getAttendanceStats(s.id)}%` }}
                              ></div>
                            </div>
                            <span className="text-sm font-bold text-slate-600">{getAttendanceStats(s.id)}%</span>
                          </div>
                        </td>
                        <td className="px-6 py-5 text-slate-500 text-sm font-medium">{s.emergencyContact}</td>
                        <td className="px-6 py-5 text-right">
                          <button onClick={() => storage.removeStudent(s.id).then(loadAllData)} className="p-2 text-slate-300 hover:text-rose-500 transition opacity-0 group-hover:opacity-100">
                            <Trash2 size={18} />
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
              {filteredStudents.length === 0 && (
                <div className="p-20 text-center text-slate-400 italic">No hay alumnos en este grupo.</div>
              )}
            </div>
          </div>
        )}

        {/* TAB: ATTENDANCE (Taking attendance for selected group) */}
        {activeTab === 'ATTENDANCE' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
              <div>
                <h2 className="text-2xl font-black text-slate-800">Toma de Asistencia</h2>
                <p className="text-slate-500 text-sm">Marca los alumnos presentes en el entrenamiento de hoy</p>
              </div>
              <div className="flex gap-2 w-full md:w-auto">
                <input 
                  type="date" 
                  className="p-3 bg-white border border-slate-200 rounded-xl font-bold text-slate-700 outline-none shadow-sm"
                  value={attendanceDate}
                  onChange={e => setAttendanceDate(e.target.value)}
                />
                <select 
                  className="p-3 bg-white border border-slate-200 rounded-xl font-bold text-indigo-600 outline-none shadow-sm"
                  value={selectedGroupId}
                  onChange={e => { setSelectedGroupId(e.target.value); setPresentIds(new Set()); }}
                >
                  {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4">
              {filteredStudents.map(s => (
                <div 
                  key={s.id} 
                  onClick={() => {
                    const n = new Set(presentIds);
                    if (n.has(s.id)) n.delete(s.id); else n.add(s.id);
                    setPresentIds(n);
                  }}
                  className={`relative overflow-hidden cursor-pointer p-5 rounded-3xl border-2 transition-all duration-300 flex flex-col gap-3 group ${presentIds.has(s.id) ? 'bg-emerald-50 border-emerald-500 shadow-lg translate-y-[-4px]' : 'bg-white border-slate-100 hover:border-indigo-200'}`}
                >
                  <div className="flex justify-between items-center">
                    <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black transition-colors ${presentIds.has(s.id) ? 'bg-emerald-500 text-white' : 'bg-slate-50 text-slate-400 group-hover:bg-indigo-50 group-hover:text-indigo-400'}`}>
                      {presentIds.has(s.id) ? <CheckCircle size={20} /> : s.firstName[0]}
                    </div>
                    <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded ${presentIds.has(s.id) ? 'bg-emerald-200 text-emerald-700' : 'bg-slate-100 text-slate-400'}`}>
                      {presentIds.has(s.id) ? 'Presente' : 'Ausente'}
                    </span>
                  </div>
                  <div>
                    <div className="font-black text-slate-800 truncate">{s.firstName} {s.lastName}</div>
                    <div className="text-xs text-slate-400">{s.position}</div>
                  </div>
                </div>
              ))}
              {filteredStudents.length === 0 && (
                <div className="col-span-full py-20 text-center text-slate-400 italic bg-white rounded-3xl border border-dashed">
                  Selecciona un grupo con alumnos para pasar lista.
                </div>
              )}
            </div>

            <div className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-6">
              <div className="flex-1 w-full">
                <label className="block text-xs font-black uppercase tracking-widest text-slate-400 mb-2">Notas del entrenamiento</label>
                <textarea 
                  placeholder="Ej: Trabajamos la presión alta..." 
                  className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 transition h-20"
                  value={attNotes}
                  onChange={e => setAttNotes(e.target.value)}
                />
              </div>
              <div className="w-full md:w-auto text-center space-y-2">
                <div className="text-xs font-bold text-slate-500">
                  <span className="text-emerald-600">{presentIds.size}</span> / {filteredStudents.length} presentes
                </div>
                <button 
                  onClick={saveAttendance}
                  disabled={attendanceSaved || filteredStudents.length === 0}
                  className={`w-full md:w-auto px-12 py-5 rounded-2xl font-black text-white transition-all shadow-xl active:scale-95 ${attendanceSaved ? 'bg-emerald-600 scale-105' : 'bg-slate-900 hover:bg-slate-800 disabled:opacity-30'}`}
                >
                  {attendanceSaved ? '¡LISTA GUARDADA!' : 'CONFIRMAR ASISTENCIA'}
                </button>
              </div>
            </div>
          </div>
        )}

        {/* TAB: HISTORY (Attendance history) */}
        {activeTab === 'HISTORY' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-black text-slate-800">Historial de Sesiones</h2>
            <div className="space-y-4">
              {attendanceRecords.slice().reverse().map(record => {
                const group = groups.find(g => g.id === record.groupId);
                return (
                  <div key={record.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div className="flex items-center gap-4">
                      <div className="w-14 h-14 bg-indigo-50 text-indigo-600 rounded-2xl flex flex-col items-center justify-center">
                        <span className="text-xs font-black leading-none">{record.date.split('-')[2]}</span>
                        <span className="text-[10px] uppercase font-bold">{new Date(record.date).toLocaleString('default', { month: 'short' })}</span>
                      </div>
                      <div>
                        <h4 className="font-black text-slate-800 text-lg">{group?.name || 'Grupo Eliminado'}</h4>
                        <p className="text-slate-400 text-sm flex items-center gap-2">
                          <Users size={14} /> {record.presentStudentIds.length} presentes • {record.sessionNotes || 'Sin notas'}
                        </p>
                      </div>
                    </div>
                    <div className="flex gap-2 w-full md:w-auto">
                      <button className="flex-1 md:flex-none px-4 py-2 text-xs font-bold text-indigo-600 bg-indigo-50 rounded-lg hover:bg-indigo-100 transition">Ver Detalle</button>
                    </div>
                  </div>
                );
              })}
              {attendanceRecords.length === 0 && <p className="text-center text-slate-400 py-20 italic">No hay registros previos.</p>}
            </div>
          </div>
        )}
      </div>

      {/* MODALS (Using standard HTML portals conceptually) */}

      {/* Group Modal */}
      {showGroupModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-white w-full max-w-lg rounded-[2.5rem] p-8 shadow-2xl space-y-6 animate-scale-in">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-800">Nuevo Grupo</h3>
              <button onClick={() => setShowGroupModal(false)} className="p-2 text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <form onSubmit={handleCreateGroup} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Nombre de la categoría</label>
                <input required placeholder="Ej: Alevines 2014" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={groupForm.name} onChange={e => setGroupForm({...groupForm, name: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Nivel / Rango de edad</label>
                <select className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={groupForm.level} onChange={e => setGroupForm({...groupForm, level: e.target.value as DifficultyLevel})}>
                  {Object.values(DifficultyLevel).map(l => <option key={l} value={l}>{t(`diff.${l}`)}</option>)}
                </select>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Observaciones / Horario</label>
                <textarea placeholder="Lunes y Miércoles 18:00h" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 h-24" value={groupForm.description} onChange={e => setGroupForm({...groupForm, description: e.target.value})} />
              </div>
              <button className="w-full bg-indigo-600 text-white py-5 rounded-2xl font-black text-lg hover:bg-indigo-700 transition shadow-xl shadow-indigo-100">CREAR CATEGORÍA</button>
            </form>
          </div>
        </div>
      )}

      {/* Student Modal */}
      {showStudentModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-white w-full max-w-xl rounded-[2.5rem] p-8 shadow-2xl space-y-6 animate-scale-in">
            <div className="flex justify-between items-center">
              <h3 className="text-2xl font-black text-slate-800">Registro de Alumno</h3>
              <button onClick={() => setShowStudentModal(false)} className="p-2 text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <form onSubmit={handleRegisterStudent} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <input required placeholder="Nombre" className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={studentForm.firstName} onChange={e => setStudentForm({...studentForm, firstName: e.target.value})} />
                <input required placeholder="Apellidos" className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={studentForm.lastName} onChange={e => setStudentForm({...studentForm, lastName: e.target.value})} />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input type="number" placeholder="Edad" className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={studentForm.age || ''} onChange={e => setStudentForm({...studentForm, age: parseInt(e.target.value)})} />
                <select required className="p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={studentForm.groupId} onChange={e => setStudentForm({...studentForm, groupId: e.target.value})}>
                  <option value="">-- Grupo / Categoría --</option>
                  {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
              </div>
              <input placeholder={`Posición (${sport.name})`} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={studentForm.position} onChange={e => setStudentForm({...studentForm, position: e.target.value})} />
              <input placeholder="Teléfono de Emergencia (Padre/Madre/Tutor)" className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={studentForm.emergencyContact} onChange={e => setStudentForm({...studentForm, emergencyContact: e.target.value})} />
              <button className="w-full bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-slate-800 transition shadow-xl">GUARDAR FICHA</button>
            </form>
          </div>
        </div>
      )}

    </div>
  );
};

export default StudentsView;

import React, { useState } from 'react';
import { LayoutDashboard, Users, Trophy, CalendarDays, Menu, X, Languages, Settings, ClipboardCheck } from 'lucide-react';
import StudentsView from './components/StudentsView';
import GamesView from './components/GamesView';
import SessionsView from './components/SessionsView';
import DashboardView from './components/DashboardView';
import SettingsView from './components/SettingsView';
import { ViewState } from './types';
import { useLanguage } from './LanguageContext';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const { language, setLanguage, t } = useLanguage();

  const navItems = [
    { id: 'DASHBOARD', label: 'Resumen', icon: <LayoutDashboard size={20} /> },
    { id: 'STUDENTS', label: 'Equipos & Lista', icon: <Users size={20} /> },
    { id: 'GAMES', label: 'Biblioteca', icon: <Trophy size={20} /> },
    { id: 'SESSIONS', label: 'Calendario', icon: <CalendarDays size={20} /> },
    { id: 'SETTINGS', label: 'Ajustes', icon: <Settings size={20} /> },
  ];

  const renderView = () => {
    switch (currentView) {
      case 'DASHBOARD': return <DashboardView onNavigate={(v) => setCurrentView(v)} />;
      case 'STUDENTS': return <StudentsView />;
      case 'GAMES': return <GamesView />;
      case 'SESSIONS': return <SessionsView />;
      case 'SETTINGS': return <SettingsView />;
      default: return <DashboardView onNavigate={(v) => setCurrentView(v)} />;
    }
  };

  const toggleLanguage = () => {
    setLanguage(language === 'en' ? 'es' : 'en');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row font-sans selection:bg-indigo-100 selection:text-indigo-900">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b border-slate-200 p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="font-black text-xl flex items-center gap-2 text-slate-900 tracking-tighter">
          <div className="bg-slate-900 text-white p-1 rounded-lg"><Trophy size={18} /></div> 
          {t('app.name')}
        </h1>
        <div className="flex items-center gap-2">
          <button onClick={toggleLanguage} className="text-[10px] font-black bg-slate-100 px-2 py-1 rounded border border-slate-200 uppercase">
            {language}
          </button>
          <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 bg-slate-900 text-white rounded-xl">
            {mobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>
      </div>

      {/* Sidebar Navigation */}
      <aside className={`${mobileMenuOpen ? 'fixed inset-0 bg-white z-[100]' : 'hidden'} md:block w-full md:w-72 bg-white flex-shrink-0 transition-all duration-300 md:h-screen sticky top-0 border-r border-slate-100 shadow-sm`}>
        <div className="p-8 hidden md:block border-b border-slate-50 mb-6">
          <h1 className="text-3xl font-black text-slate-900 flex items-center gap-3 tracking-tighter">
            <div className="bg-indigo-600 p-2 rounded-2xl shadow-lg shadow-indigo-100"><Trophy size={28} className="text-white" /></div>
            {t('app.name')}
          </h1>
          <p className="text-[10px] text-slate-400 mt-2 uppercase font-black tracking-[0.2em]">{t('app.desc')}</p>
        </div>

        <nav className="px-4 py-2 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => {
                setCurrentView(item.id as ViewState);
                setMobileMenuOpen(false);
              }}
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-[1.5rem] transition-all duration-300 group
                ${currentView === item.id 
                  ? 'bg-slate-900 text-white shadow-2xl shadow-slate-200' 
                  : 'hover:bg-slate-50 text-slate-400 hover:text-slate-900'
                }`}
            >
              <div className={`p-2 rounded-xl transition-colors ${currentView === item.id ? 'bg-indigo-500/20 text-white' : 'bg-slate-50 text-slate-400 group-hover:bg-white group-hover:text-indigo-600'}`}>
                {item.icon}
              </div>
              <span className="font-black text-sm tracking-tight">{item.label}</span>
            </button>
          ))}
        </nav>

        <div className="absolute bottom-0 w-full p-8 hidden md:block">
          <div className="bg-indigo-50 rounded-[2rem] p-6 border border-indigo-100">
            <h4 className="text-indigo-900 font-black text-xs uppercase tracking-widest mb-1">PRO Version</h4>
            <p className="text-[10px] text-indigo-600 font-bold mb-3">Sync con Postgres Cloud activado.</p>
            <div className="h-1.5 w-full bg-indigo-200 rounded-full overflow-hidden">
              <div className="h-full bg-indigo-600 w-3/4 rounded-full"></div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto h-screen scroll-smooth bg-slate-50/50">
        <div className="max-w-6xl mx-auto p-6 md:p-12">
          <header className="mb-10 flex justify-between items-end">
            <div>
              <div className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-2">Coach Dashboard</div>
              <h2 className="text-5xl font-black text-slate-900 tracking-tighter">
                {navItems.find(i => i.id === currentView)?.label}
              </h2>
            </div>
            <div className="hidden md:flex items-center gap-3">
              <button 
                onClick={toggleLanguage}
                className="bg-white border border-slate-200 px-6 py-3 rounded-2xl text-slate-700 font-black text-xs uppercase tracking-widest hover:shadow-md transition"
              >
                {language === 'en' ? 'EN' : 'ES'}
              </button>
            </div>
          </header>

          <div className="animate-fade-in">
            {renderView()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

export enum SportCategory {
  GENERAL = 'General',
  WARMUP = 'Warm Up',
  TECHNICAL = 'Technical',
  TACTICAL = 'Tactical',
  PHYSICAL = 'Physical'
}

export enum DifficultyLevel {
  U5 = 'U5',           
  U7 = 'U7',           
  U9 = 'U9',           
  U12 = 'U12',         
  U16 = 'U16',         
  SENIOR = 'SENIOR',   
  ALL_AGES = 'ALL_AGES'
}

export interface Group {
  id: string;
  name: string;
  description?: string;
  level?: DifficultyLevel;
  createdAt: string;
}

export interface Student {
  id: string;
  groupId: string;
  firstName: string;
  lastName: string;
  age: number;
  position: string;
  emergencyContact: string;
  notes?: string;
  active: boolean;
}

export interface AttendanceRecord {
  id: string;
  date: string;
  groupId: string;
  presentStudentIds: string[];
  sessionNotes?: string;
}

export interface Game {
  id: string;
  title: string;
  description: string;
  category: SportCategory;
  difficulty: DifficultyLevel;
  durationMin: number;
  tags: string[];
}

export interface SessionItem {
  gameId: string;
  durationMin: number;
  notes?: string;
}

export interface Session {
  id: string;
  groupId: string; // Relación con el grupo
  title: string;
  date: string;
  items: SessionItem[];
  totalDuration: number;
  description?: string;
}

export interface SportConfig {
  name: string;
  primaryColor: string;
}

export interface DashboardStats {
  totalStudents: number;
  totalGroups: number;
  totalGames: number;
  sessionsThisMonth: number;
  averageAttendance: number;
}

export type ViewState = 'DASHBOARD' | 'STUDENTS' | 'GAMES' | 'SESSIONS' | 'SETTINGS';

import React, { useState, useEffect } from 'react';
import { 
  Plus, Calendar, Trash2, Clock, PlayCircle, 
  Pencil, Eye, X, ChevronRight, Layout, 
  Target, Info, ArrowLeft
} from 'lucide-react';
import { Session, Game, SessionItem, DifficultyLevel, Group } from '../types';
import * as storage from '../services/storage';
import { useLanguage } from '../LanguageContext';

const SessionsView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'CREATE' | 'LIST'>('LIST');
  const [sessions, setSessions] = useState<Session[]>([]);
  const [games, setGames] = useState<Game[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [loading, setLoading] = useState(true);
  const { t } = useLanguage();

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [sessionTitle, setSessionTitle] = useState('');
  const [selectedGroupId, setSelectedGroupId] = useState('');
  const [sessionDate, setSessionDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionDescription, setSessionDescription] = useState('');
  const [selectedItems, setSelectedItems] = useState<SessionItem[]>([]);

  // Details Modal State
  const [selectedSession, setSelectedSession] = useState<Session | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [sessionsData, gamesData, groupsData] = await Promise.all([
      storage.getSessions(),
      storage.getGames(),
      storage.getGroups()
    ]);
    setSessions(sessionsData);
    setGames(gamesData);
    setGroups(groupsData);
    if (groupsData.length > 0 && !selectedGroupId) setSelectedGroupId(groupsData[0].id);
    setLoading(false);
  };

  const addGameToSession = (game: Game) => {
    setSelectedItems(prev => [
      ...prev,
      { gameId: game.id, durationMin: game.durationMin }
    ]);
  };

  const removeGameFromSession = (index: number) => {
    const newItems = [...selectedItems];
    newItems.splice(index, 1);
    setSelectedItems(newItems);
  };

  const updateItemDuration = (index: number, minutes: number) => {
    const newItems = [...selectedItems];
    newItems[index].durationMin = minutes;
    setSelectedItems(newItems);
  };

  const calculateTotalDuration = (items: SessionItem[]) => {
    return items.reduce((acc, curr) => acc + curr.durationMin, 0);
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sessionTitle || !selectedGroupId) return;

    const newSession: Session = {
      id: editingId || crypto.randomUUID(),
      groupId: selectedGroupId,
      title: sessionTitle,
      date: sessionDate,
      description: sessionDescription,
      items: selectedItems,
      totalDuration: calculateTotalDuration(selectedItems)
    };

    await storage.addSession(newSession);
    resetForm();
    loadData();
    setActiveTab('LIST');
  };

  const resetForm = () => {
    setEditingId(null);
    setSessionTitle('');
    setSessionDescription('');
    setSessionDate(new Date().toISOString().split('T')[0]);
    setSelectedItems([]);
  };

  const handleEdit = (session: Session) => {
    setEditingId(session.id);
    setSessionTitle(session.title);
    setSelectedGroupId(session.groupId);
    setSessionDescription(session.description || '');
    setSessionDate(session.date);
    setSelectedItems(session.items);
    setActiveTab('CREATE');
  };

  const getDifficultyColorClass = (level?: DifficultyLevel) => {
    switch (level) {
      case DifficultyLevel.SENIOR: return 'text-red-600 bg-red-50';
      case DifficultyLevel.U16: return 'text-orange-600 bg-orange-50';
      case DifficultyLevel.U12: return 'text-amber-600 bg-amber-50';
      default: return 'text-indigo-600 bg-indigo-50';
    }
  };

  if (loading) return (
    <div className="flex flex-col items-center justify-center h-64 space-y-4">
      <div className="w-12 h-12 border-4 border-slate-900 border-t-transparent rounded-full animate-spin"></div>
      <p className="text-slate-500 font-bold">Cargando planificación...</p>
    </div>
  );

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Sub Nav */}
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200">
        <button
          onClick={() => setActiveTab('LIST')}
          className={`flex-1 px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'LIST' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Calendar size={18} /> {t('sessions.history')}
        </button>
        <button
          onClick={() => { setActiveTab('CREATE'); if(!editingId) resetForm(); }}
          className={`flex-1 px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'CREATE' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Plus size={18} /> {editingId ? 'Editar Sesión' : t('sessions.create')}
        </button>
      </div>

      <div className="min-h-[600px]">
        {/* LIST VIEW */}
        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <h2 className="text-2xl font-black text-slate-800">Próximos Entrenamientos</h2>
            </div>

            <div className="grid grid-cols-1 gap-4">
              {sessions.length === 0 && (
                <div className="py-20 text-center text-slate-400 bg-white rounded-[2rem] border border-dashed border-slate-200">
                  <Calendar size={48} className="mx-auto mb-4 opacity-10" />
                  <p className="font-bold">No hay sesiones planificadas.</p>
                </div>
              )}

              {sessions.slice().reverse().map(session => {
                const group = groups.find(g => g.id === session.groupId);
                return (
                  <div key={session.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl hover:border-indigo-100 transition group flex flex-col md:flex-row items-center gap-6">
                    <div className="w-20 h-20 bg-slate-50 rounded-3xl flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                      <span className="text-sm font-black uppercase">{new Date(session.date).toLocaleString('default', { month: 'short' })}</span>
                      <span className="text-2xl font-black">{session.date.split('-')[2]}</span>
                    </div>

                    <div className="flex-1 text-center md:text-left">
                      <div className="flex flex-wrap justify-center md:justify-start gap-2 mb-2">
                        <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded tracking-wider">
                          {group?.name || 'Sin Grupo'}
                        </span>
                        <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-[10px] font-black uppercase rounded tracking-wider flex items-center gap-1">
                          <Clock size={10} /> {session.totalDuration} min
                        </span>
                      </div>
                      <h3 className="text-xl font-black text-slate-800 group-hover:text-indigo-600 transition-colors">{session.title}</h3>
                      <p className="text-slate-400 text-sm line-clamp-1">{session.description || 'Sin descripción adicional'}</p>
                    </div>

                    <div className="flex gap-2">
                      <button 
                        onClick={() => setSelectedSession(session)}
                        className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-blue-50 hover:text-blue-600 transition"
                      >
                        <Eye size={20} />
                      </button>
                      <button 
                        onClick={() => handleEdit(session)}
                        className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-indigo-50 hover:text-indigo-600 transition"
                      >
                        <Pencil size={20} />
                      </button>
                      <button 
                        onClick={() => storage.removeSession(session.id).then(loadData)}
                        className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-rose-50 hover:text-rose-600 transition"
                      >
                        <Trash2 size={20} />
                      </button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {/* CREATE/EDIT VIEW */}
        {activeTab === 'CREATE' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            {/* Left Col: Builder */}
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
                <div className="flex items-center gap-4 mb-4">
                  <div className="p-3 bg-indigo-600 text-white rounded-2xl">
                    <Layout size={24} />
                  </div>
                  <h2 className="text-2xl font-black text-slate-800">
                    {editingId ? 'Editar Planificación' : 'Nueva Sesión'}
                  </h2>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Título de la Sesión</label>
                    <input
                      type="text"
                      value={sessionTitle}
                      onChange={e => setSessionTitle(e.target.value)}
                      className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
                      placeholder="Ej: Entrenamiento Táctico Lunes"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Grupo Asignado</label>
                    <select
                      value={selectedGroupId}
                      onChange={e => setSelectedGroupId(e.target.value)}
                      className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-indigo-600"
                    >
                      <option value="">Seleccionar Grupo...</option>
                      {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                    </select>
                  </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Fecha</label>
                    <input
                      type="date"
                      value={sessionDate}
                      onChange={e => setSessionDate(e.target.value)}
                      className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500"
                    />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Duración Total</label>
                    <div className="w-full p-4 bg-indigo-50 border border-indigo-100 rounded-2xl flex items-center justify-between">
                      <span className="font-black text-indigo-600">{calculateTotalDuration(selectedItems)} minutos</span>
                      <Clock className="text-indigo-300" />
                    </div>
                  </div>
                </div>

                <div className="space-y-1">
                  <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Objetivos de la sesión</label>
                  <textarea
                    value={sessionDescription}
                    onChange={e => setSessionDescription(e.target.value)}
                    className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 h-24"
                    placeholder="Describe lo que quieres lograr hoy..."
                  />
                </div>
              </div>

              {/* TIMELINE */}
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[300px]">
                <h3 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-2">
                  <Target className="text-indigo-600" /> Línea de Tiempo
                </h3>

                {selectedItems.length === 0 ? (
                  <div className="h-40 flex flex-col items-center justify-center text-slate-300 border-2 border-dashed border-slate-100 rounded-[2rem]">
                    <PlayCircle size={40} className="mb-2 opacity-10"/>
                    <p className="font-bold">Añade ejercicios desde tu biblioteca</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {selectedItems.map((item, idx) => {
                      const game = games.find(g => g.id === item.gameId);
                      if (!game) return null;
                      return (
                        <div key={idx} className="bg-slate-50 p-4 rounded-3xl border border-slate-100 flex items-center gap-4 group">
                          <div className="bg-white text-indigo-600 w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-sm shrink-0">
                            {idx + 1}
                          </div>
                          <div className="flex-1">
                            <div className="font-bold text-slate-800">{game.title}</div>
                            <div className="text-[9px] font-black uppercase tracking-widest text-slate-400">
                              {t(`cat.${game.category}`)}
                            </div>
                          </div>
                          <div className="flex items-center gap-2">
                            <input 
                              type="number"
                              value={item.durationMin}
                              onChange={(e) => updateItemDuration(idx, parseInt(e.target.value))}
                              className="w-16 p-2 bg-white border border-slate-100 rounded-xl text-center font-bold text-indigo-600 outline-none focus:ring-2 focus:ring-indigo-500"
                            />
                            <span className="text-[10px] font-black uppercase text-slate-400">min</span>
                          </div>
                          <button onClick={() => removeGameFromSession(idx)} className="p-2 text-slate-300 hover:text-rose-500 transition">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      );
                    })}
                  </div>
                )}

                <div className="mt-8 pt-6 border-t border-slate-50 flex gap-4">
                  <button 
                    onClick={handleCreate}
                    disabled={!sessionTitle || !selectedGroupId}
                    className="flex-1 bg-slate-900 text-white py-5 rounded-[1.5rem] font-black text-lg hover:bg-slate-800 transition shadow-xl disabled:opacity-20"
                  >
                    {editingId ? 'ACTUALIZAR PLAN' : 'GUARDAR ENTRENAMIENTO'}
                  </button>
                  {editingId && (
                    <button onClick={resetForm} className="px-8 py-5 bg-slate-100 text-slate-400 rounded-[1.5rem] font-black hover:bg-slate-200 transition">
                      CANCELAR
                    </button>
                  )}
                </div>
              </div>
            </div>

            {/* Right Col: Picker */}
            <div className="space-y-6">
              <div className="bg-indigo-600 p-8 rounded-[2.5rem] shadow-xl text-white">
                <h3 className="text-xl font-black mb-4">Tu Biblioteca</h3>
                <p className="text-indigo-100 text-xs mb-6 font-medium">Haz clic en un ejercicio para añadirlo a la sesión actual.</p>
                <div className="space-y-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                  {games.map(game => (
                    <div key={game.id} className="p-4 bg-white/10 border border-white/10 rounded-2xl hover:bg-white hover:text-indigo-600 transition cursor-pointer group flex justify-between items-center" onClick={() => addGameToSession(game)}>
                      <div>
                        <div className="font-bold text-sm">{game.title}</div>
                        <div className="text-[9px] font-black uppercase opacity-60 tracking-wider">{game.durationMin} min • {t(`cat.${game.category}`)}</div>
                      </div>
                      <Plus size={16} className="opacity-0 group-hover:opacity-100" />
                    </div>
                  ))}
                  {games.length === 0 && <p className="text-sm text-indigo-200 italic opacity-50">Crea juegos primero en la biblioteca.</p>}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

       {/* DETAILS MODAL */}
       {selectedSession && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-white rounded-[3rem] max-w-2xl w-full max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-scale-in">
            <div className="p-10 bg-slate-900 text-white relative">
              <button 
                onClick={() => setSelectedSession(null)} 
                className="absolute top-8 right-8 p-2 bg-white/10 hover:bg-white/20 text-white rounded-full transition"
              >
                <X size={24} />
              </button>
              <div className="flex gap-2 mb-4">
                 <span className="px-3 py-1 bg-indigo-500 text-white text-[10px] font-black uppercase rounded tracking-widest">
                    {groups.find(g => g.id === selectedSession.groupId)?.name}
                 </span>
                 <span className="px-3 py-1 bg-white/10 text-white text-[10px] font-black uppercase rounded tracking-widest">
                    {selectedSession.totalDuration} min
                 </span>
              </div>
              <h2 className="text-3xl font-black tracking-tighter">{selectedSession.title}</h2>
              <p className="text-slate-400 mt-2 font-medium">{new Date(selectedSession.date).toLocaleDateString()}</p>
            </div>

            <div className="flex-1 overflow-y-auto p-10 space-y-8">
              {selectedSession.description && (
                <div className="space-y-3">
                   <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Objetivos</h3>
                   <p className="text-slate-600 leading-relaxed font-medium bg-slate-50 p-6 rounded-3xl border border-slate-100">
                      {selectedSession.description}
                   </p>
                </div>
              )}

              <div className="space-y-4">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">Estructura del entrenamiento</h3>
                <div className="space-y-3">
                   {selectedSession.items.map((item, idx) => {
                     const game = games.find(g => g.id === item.gameId);
                     return (
                       <div key={idx} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-start gap-4">
                          <div className="bg-indigo-50 text-indigo-600 w-12 h-12 rounded-2xl flex items-center justify-center font-black shrink-0">
                            {idx + 1}
                          </div>
                          <div className="flex-1">
                            {game ? (
                              <>
                                <h4 className="font-black text-slate-800 text-lg">{game.title}</h4>
                                <div className="flex gap-2 text-[9px] font-black uppercase tracking-widest text-slate-400 mb-2">
                                  <span>{t(`cat.${game.category}`)}</span>
                                  <span>•</span>
                                  <span>{item.durationMin} minutos</span>
                                </div>
                                <p className="text-sm text-slate-500 line-clamp-2">{game.description}</p>
                              </>
                            ) : (
                              <span className="text-rose-500 italic">Ejercicio eliminado de la biblioteca</span>
                            )}
                          </div>
                       </div>
                     )
                   })}
                </div>
              </div>
            </div>

            <div className="p-8 border-t border-slate-50 bg-slate-50 text-center">
              <button 
                onClick={() => setSelectedSession(null)}
                className="bg-slate-900 text-white px-10 py-4 rounded-2xl font-black text-sm tracking-widest uppercase hover:bg-slate-800 transition"
              >
                Cerrar Detalle
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SessionsView;

