import { GoogleGenAI, Type } from "@google/genai";
import { SportCategory, DifficultyLevel, Student, Group, Game, Session } from "../types";
import * as storage from "./storage";

export interface AIGameSuggestion {
  title: string;
  description: string;
  category: SportCategory;
  difficulty: DifficultyLevel;
  durationMin: number;
}

export const generateGameIdea = async (
  prompt: string, 
  language: 'en' | 'es' = 'en',
): Promise<AIGameSuggestion> => {
  const sportConfig = storage.getSportConfig();
  const langPrompt = language === 'es' ? 'Salida puramente en Español.' : 'Output purely in English.';
  const finalPrompt = `Crea un ejercicio o juego de entrenamiento para ${sportConfig.name} enfocado en: ${prompt}. Asegúrate de que las reglas sean claras y acordes al deporte ${sportConfig.name}. ${langPrompt}`;

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: finalPrompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            title: { type: Type.STRING },
            description: { type: Type.STRING },
            category: { type: Type.STRING },
            difficulty: { type: Type.STRING },
            durationMin: { type: Type.INTEGER }
          },
          required: ["title", "description", "category", "difficulty", "durationMin"]
        }
      }
    });
    return JSON.parse(response.text || '{}') as AIGameSuggestion;
  } catch (error) {
    console.error(error);
    throw error;
  }
};

export const consultAICoach = async (
  userMessage: string,
  dataContext: { students: Student[], groups: Group[], games: Game[], sessions: Session[] },
  language: 'en' | 'es' = 'en'
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const sport = storage.getSportConfig();

  const systemInstruction = `
    Eres un Consultor Experto en Gestión Deportiva para el club "AIM Sports". 
    Tu deporte actual es: ${sport.name}.
    Idioma de respuesta: ${language === 'es' ? 'Español' : 'Inglés'}.

    Tienes acceso a los siguientes datos (resumen):
    - Alumnos totales: ${dataContext.students.length}
    - Grupos: ${dataContext.groups.map(g => g.name).join(', ')}
    - Ejercicios en biblioteca: ${dataContext.games.length}
    - Sesiones planificadas: ${dataContext.sessions.length}

    Tu tarea es ayudar al entrenador a gestionar el club, analizar la asistencia, sugerir calendarios de entrenamiento o responder dudas técnicas.
    Sé profesional, conciso y motivador. Usa Markdown para formatear las respuestas.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: userMessage,
      config: { systemInstruction }
    });
    return response.text || "No response";
  } catch (error) {
    return "Error connecting to AI Coach. Please check your API key.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Send, Sparkles, MessageSquare, TrendingUp, Calendar, Trash2 } from 'lucide-react';
import * as storage from '../services/storage';
import { consultAICoach } from '../services/geminiService';
import { useLanguage } from '../LanguageContext';

interface Message {
  role: 'user' | 'ai';
  text: string;
}

const AICoachView: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const { t, language } = useLanguage();
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setMessages([{ role: 'ai', text: t('ai.welcome') }]);
  }, []);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = async (overridePrompt?: string) => {
    const textToSend = overridePrompt || input;
    if (!textToSend.trim() || loading) return;

    const userMsg: Message = { role: 'user', text: textToSend };
    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setLoading(true);

    try {
      const students = await storage.getStudents();
      const groups = await storage.getGroups();
      const games = await storage.getGames();
      const sessions = await storage.getSessions();

      const response = await consultAICoach(textToSend, { students, groups, games, sessions }, language);
      setMessages(prev => [...prev, { role: 'ai', text: response }]);
    } catch (e) {
      setMessages(prev => [...prev, { role: 'ai', text: "Error: " + e }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-4xl mx-auto h-[calc(100vh-250px)] flex flex-col bg-white rounded-[2.5rem] shadow-xl border border-slate-100 overflow-hidden animate-fade-in">
      {/* Header */}
      <div className="bg-slate-900 p-8 text-white flex items-center justify-between">
        <div className="flex items-center gap-4">
          <div className="bg-indigo-500 p-3 rounded-2xl shadow-lg shadow-indigo-500/20">
            <Sparkles className="text-white" size={24} />
          </div>
          <div>
            <h2 className="text-xl font-black tracking-tight">{t('ai.title')}</h2>
            <p className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">{t('ai.subtitle')}</p>
          </div>
        </div>
        <button onClick={() => setMessages([{ role: 'ai', text: t('ai.welcome') }])} className="p-2 hover:bg-white/10 rounded-xl transition">
          <Trash2 size={20} className="text-slate-400" />
        </button>
      </div>

      {/* Messages */}
      <div ref={scrollRef} className="flex-1 overflow-y-auto p-8 space-y-6 bg-slate-50/30">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-slide-up`}>
            <div className={`max-w-[80%] p-5 rounded-3xl font-medium text-sm leading-relaxed shadow-sm
              ${m.role === 'user' 
                ? 'bg-slate-900 text-white rounded-tr-none' 
                : 'bg-white text-slate-700 border border-slate-100 rounded-tl-none'}`}>
              {m.text.split('\n').map((line, j) => <p key={j} className={j > 0 ? 'mt-2' : ''}>{line}</p>)}
            </div>
          </div>
        ))}
        {loading && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-white border border-slate-100 p-5 rounded-3xl rounded-tl-none flex items-center gap-2">
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce"></div>
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-75"></div>
              <div className="w-2 h-2 bg-indigo-500 rounded-full animate-bounce delay-150"></div>
              <span className="text-[10px] font-black text-slate-400 ml-2 uppercase tracking-widest">{t('ai.thinking')}</span>
            </div>
          </div>
        )}
      </div>

      {/* Suggested Actions */}
      <div className="px-8 py-4 bg-white border-t border-slate-50 flex gap-2 overflow-x-auto no-scrollbar">
        <button onClick={() => handleSend(t('ai.suggest.plan'))} className="shrink-0 px-4 py-2 bg-indigo-50 text-indigo-600 rounded-xl text-xs font-black border border-indigo-100 hover:bg-indigo-100 transition flex items-center gap-2">
          <Calendar size={14} /> {t('ai.suggest.plan')}
        </button>
        <button onClick={() => handleSend(t('ai.suggest.analyze'))} className="shrink-0 px-4 py-2 bg-emerald-50 text-emerald-600 rounded-xl text-xs font-black border border-emerald-100 hover:bg-emerald-100 transition flex items-center gap-2">
          <TrendingUp size={14} /> {t('ai.suggest.analyze')}
        </button>
