              <span className={`text-[10px] font-black px-3 py-1 rounded-full uppercase tracking-widest
                ${config.isPremium ? 'bg-white/20 text-white' : 'bg-slate-100 text-slate-400'}`}>
                {config.isPremium ? 'Active' : 'Free'}
