            </div>

            <div className="space-y-6">
              <div className="bg-white/5 p-6 rounded-[2rem] border border-white/10">
                <p className={`text-xs font-bold uppercase tracking-widest mb-1 ${config.isPremium ? 'text-indigo-200' : 'text-slate-400'}`}>Current Plan</p>
                <h4 className="text-3xl font-black tracking-tighter">
                   {config.isPremium ? 'Coach Pro' : 'Free Starter'}
                </h4>
                <p className="mt-2 text-sm font-medium opacity-70">
                   {config.isPremium ? t('premium.status.pro') : t('premium.desc')}
                </p>
              </div>

              {config.isPremium ? (
                <div className="space-y-4">
                  <div className="flex items-center gap-3 text-sm font-bold bg-white/10 p-4 rounded-2xl">
                     <ShieldCheck size={20} className="text-indigo-300" />
                     Suscripción gestionada vía AIM Cloud
                  </div>
                </div>
              ) : (
                <div className="space-y-3">
                   <div className="flex items-center gap-3 text-xs font-bold"><CheckCircle size={16} className="text-indigo-500" /> IA Sin límites</div>
                   <div className="flex items-center gap-3 text-xs font-bold"><CheckCircle size={16} className="text-indigo-500" /> Soporte prioritario 24/7</div>
                </div>
              )}
            </div>
          </div>

          <div className="pt-10">
            <button 
              onClick={togglePremium}
              className={`w-full py-5 rounded-2xl font-black transition-all shadow-xl flex items-center justify-center gap-3 
                ${config.isPremium 
                  ? 'bg-white text-indigo-700 hover:bg-slate-50' 
                  : 'bg-indigo-600 text-white hover:bg-indigo-700'}`}
            >
              {config.isPremium ? (
                <>Cancelar Suscripción</>
              ) : (
                <><Sparkles size={20} /> Suscribirse a Pro — $9.99</>
              )}
            </button>
          </div>
        </div>
      </div>

      {/* FOOTER INFO */}
      <div className="p-8 bg-slate-100 rounded-[2rem] border border-slate-200 text-slate-500">
        <h3 className="font-black text-slate-900 mb-2 uppercase text-xs tracking-widest">{t('settings.backend_title')}</h3>
        <p className="text-sm font-medium leading-relaxed max-w-2xl">
          {t('settings.backend_desc')} Esta arquitectura soporta escalado a miles de usuarios y procesamiento de pagos seguros.
        </p>
      </div>
    </div>
  );
};

export default SettingsView;

import React, { useState, useEffect } from 'react';
import { LayoutDashboard, Users, Trophy, CalendarDays, Menu, X, Settings, Sparkles, ShieldCheck } from 'lucide-react';
import StudentsView from './components/StudentsView';
import GamesView from './components/GamesView';
import SessionsView from './components/SessionsView';
import DashboardView from './components/DashboardView';
import SettingsView from './components/SettingsView';
import AICoachView from './components/AICoachView';
import { ViewState } from './types';
import { useLanguage } from './LanguageContext';
import * as storage from './services/storage';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('DASHBOARD');
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [isPremium, setIsPremium] = useState(storage.getSportConfig().isPremium);
  const { language, setLanguage, t } = useLanguage();

  useEffect(() => {
    const handleStorageUpdate = () => setIsPremium(storage.getSportConfig().isPremium);
    window.addEventListener('storage_updated', handleStorageUpdate);
    return () => window.removeEventListener('storage_updated', handleStorageUpdate);
  }, []);

  const navItems = [
    { id: 'DASHBOARD', label: t('nav.dashboard'), icon: <LayoutDashboard size={20} /> },
    { id: 'STUDENTS', label: t('nav.students'), icon: <Users size={20} /> },
    { id: 'GAMES', label: t('nav.games'), icon: <Trophy size={20} /> },
    { id: 'SESSIONS', label: t('nav.sessions'), icon: <CalendarDays size={20} /> },
    { id: 'AI_COACH', label: t('nav.aicoach'), icon: <Sparkles size={20} />, special: true },
    { id: 'SETTINGS', label: t('nav.settings'), icon: <Settings size={20} /> },
  ];

  const renderView = () => {
    switch (currentView) {
      case 'DASHBOARD': return <DashboardView onNavigate={(v) => setCurrentView(v)} />;
      case 'STUDENTS': return <StudentsView />;
      case 'GAMES': return <GamesView />;
      case 'SESSIONS': return <SessionsView />;
      case 'AI_COACH': return <AICoachView />;
      case 'SETTINGS': return <SettingsView />;
      default: return <DashboardView onNavigate={(v) => setCurrentView(v)} />;
    }
  };

  const toggleLanguage = () => {
    setLanguage(language === 'en' ? 'es' : 'en');
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row font-sans selection:bg-indigo-100 selection:text-indigo-900">
      {/* Mobile Header */}
      <div className="md:hidden bg-white border-b border-slate-200 p-4 flex justify-between items-center sticky top-0 z-50">
        <h1 className="font-black text-xl flex items-center gap-2 text-slate-900 tracking-tighter">
          <div className="bg-slate-900 text-white p-1 rounded-lg"><Trophy size={18} /></div> 
          {t('app.name')}
        </h1>
        <div className="flex items-center gap-2">
          {isPremium && <span className="text-[9px] font-black bg-indigo-600 px-2 py-1 rounded text-white uppercase tracking-tighter">PRO</span>}
          <button onClick={toggleLanguage} className="text-[10px] font-black bg-slate-100 px-2 py-1 rounded border border-slate-200 uppercase">
            {language}
          </button>
          <button onClick={() => setMobileMenuOpen(!mobileMenuOpen)} className="p-2 bg-slate-900 text-white rounded-xl">
            {mobileMenuOpen ? <X size={20} /> : <Menu size={20} />}
          </button>
        </div>
      </div>

      {/* Sidebar Navigation */}
      <aside className={`${mobileMenuOpen ? 'fixed inset-0 bg-white z-[100]' : 'hidden'} md:block w-full md:w-72 bg-white flex-shrink-0 transition-all duration-300 md:h-screen sticky top-0 border-r border-slate-100 shadow-sm`}>
        <div className="p-8 hidden md:block border-b border-slate-50 mb-6">
          <h1 className="text-3xl font-black text-slate-900 flex items-center gap-3 tracking-tighter">
            <div className="bg-indigo-600 p-2 rounded-2xl shadow-lg shadow-indigo-100"><Trophy size={28} className="text-white" /></div>
            {t('app.name')}
          </h1>
          <p className="text-[10px] text-slate-400 mt-2 uppercase font-black tracking-[0.2em]">{t('app.desc')}</p>
        </div>

        <nav className="px-4 py-2 space-y-1">
          {navItems.map(item => (
            <button
              key={item.id}
              onClick={() => {
                setCurrentView(item.id as ViewState);
                setMobileMenuOpen(false);
              }}
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-[1.5rem] transition-all duration-300 group
                ${currentView === item.id 
                  ? 'bg-slate-900 text-white shadow-2xl shadow-slate-200' 
                  : (item.special ? 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100' : 'hover:bg-slate-50 text-slate-400 hover:text-slate-900')
                }`}
            >
              <div className={`p-2 rounded-xl transition-colors ${currentView === item.id ? 'bg-indigo-500/20 text-white' : (item.special ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400 group-hover:bg-white group-hover:text-indigo-600')}`}>
                {item.icon}
              </div>
              <span className="font-black text-sm tracking-tight flex-1 text-left">{item.label}</span>
              {item.special && !isPremium && <Lock size={12} className="text-indigo-300" />}
            </button>
          ))}
        </nav>

        <div className="absolute bottom-0 w-full p-8 hidden md:block">
          <div className={`rounded-[2rem] p-6 border transition-all duration-500
            ${isPremium 
              ? 'bg-gradient-to-br from-indigo-600 to-purple-600 text-white border-indigo-400' 
              : 'bg-slate-900 text-white border-slate-800'}`}>
            <div className="flex items-center justify-between mb-2">
               <h4 className={`font-black text-xs uppercase tracking-widest ${isPremium ? 'text-white' : 'text-indigo-400'}`}>
                 {isPremium ? 'PRO MEMBER' : 'FREE PLAN'}
               </h4>
               {isPremium && <ShieldCheck size={16} />}
            </div>
            <p className="text-[10px] text-slate-300 font-bold mb-3">
              {isPremium ? 'Todos los servicios activos.' : 'Pásate a Pro para IA ilimitada.'}
            </p>
            {!isPremium && (
               <button 
                 onClick={() => { setCurrentView('AI_COACH'); setMobileMenuOpen(false); }}
                 className="w-full bg-indigo-600 py-2 rounded-xl text-[10px] font-black hover:bg-indigo-500 transition"
               >
                  UPGRADE NOW
               </button>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto h-screen scroll-smooth bg-slate-50/50">
        <div className="max-w-6xl mx-auto p-6 md:p-12">
          <header className="mb-10 flex justify-between items-end">
            <div>
              <div className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-2">Coach Dashboard</div>
              <h2 className="text-5xl font-black text-slate-900 tracking-tighter">
                {navItems.find(i => i.id === currentView)?.label}
              </h2>
            </div>
            <div className="hidden md:flex items-center gap-3">
              <button 
                onClick={toggleLanguage}
                className="bg-white border border-slate-200 px-6 py-3 rounded-2xl text-slate-700 font-black text-xs uppercase tracking-widest hover:shadow-md transition"
              >
                {language === 'en' ? 'EN' : 'ES'}
              </button>
            </div>
          </header>

          <div className="animate-fade-in">
            {renderView()}
          </div>
        </div>
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
/* Added Trophy to imports */
import { Plus, List, Sparkles, Trash2, Clock, BarChart, Pencil, Eye, X, Lock, Trophy } from 'lucide-react';
import { Game, SportCategory, DifficultyLevel } from '../types';
import * as storage from '../services/storage';
import { generateGameIdea } from '../services/geminiService';
import { useLanguage } from '../LanguageContext';

const GamesView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'CREATE' | 'LIST'>('LIST');
  const [games, setGames] = useState<Game[]>([]);
  const [filterDifficulty, setFilterDifficulty] = useState<DifficultyLevel | 'ALL'>('ALL');
  const [refresh, setRefresh] = useState(0);
  const [loading, setLoading] = useState(true);
  const [isPremium, setIsPremium] = useState(storage.getSportConfig().isPremium);
  const { t, language } = useLanguage();

  // AI Loading State
  const [isGenerating, setIsGenerating] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');

  // Form State
  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Game>>({
    title: '',
    description: '',
    category: SportCategory.GENERAL,
    difficulty: DifficultyLevel.ALL_AGES,
    durationMin: 15,
    tags: []
  });

  // Details Modal State
  const [selectedGame, setSelectedGame] = useState<Game | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const data = await storage.getGames();
        setGames(data);
        setIsPremium(storage.getSportConfig().isPremium);
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    loadData();

    const handleStorageUpdate = () => setIsPremium(storage.getSportConfig().isPremium);
    window.addEventListener('storage_updated', handleStorageUpdate);
    return () => window.removeEventListener('storage_updated', handleStorageUpdate);
  }, [refresh]);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title) return;

    const newGame: Game = {
      id: editingId || crypto.randomUUID(), 
      title: formData.title!,
      description: formData.description || '',
      category: formData.category || SportCategory.GENERAL,
      difficulty: formData.difficulty || DifficultyLevel.ALL_AGES,
      durationMin: formData.durationMin || 15,
      tags: formData.tags || []
    };

    await storage.addGame(newGame);
    resetForm();
    setRefresh(r => r + 1);
    setActiveTab('LIST');
  };

  const resetForm = () => {
    setEditingId(null);
    setFormData({
      title: '',
      description: '',
      category: SportCategory.GENERAL,
      difficulty: DifficultyLevel.ALL_AGES,
      durationMin: 15,
      tags: []
    });
  };

  const handleGenerateAI = async () => {
    if (!isPremium) {
       alert(t('premium.locked') + ": " + t('premium.desc'));
       return;
    }
    if (!aiPrompt) return;
    setIsGenerating(true);
    try {
      const suggestion = await generateGameIdea(aiPrompt, language);
      setFormData({
        ...formData,
        title: suggestion.title,
        description: suggestion.description,
        category: suggestion.category,
        difficulty: suggestion.difficulty,
        durationMin: suggestion.durationMin,
      });
    } catch (error) {
      alert("Failed to generate game. Please check your API Key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleEdit = (game: Game) => {
    setEditingId(game.id);
    setFormData({
      title: game.title,
      description: game.description,
      category: game.category,
      difficulty: game.difficulty,
      durationMin: game.durationMin,
      tags: game.tags
    });
    setActiveTab('CREATE');
  };

  const handleDelete = async (id: string) => {
    if(confirm('¿Seguro que quieres eliminar este ejercicio?')) {
      await storage.removeGame(id);
      setRefresh(r => r + 1);
    }
  }

  const handleTabChange = (tab: 'CREATE' | 'LIST') => {
    setActiveTab(tab);
    if (tab === 'CREATE' && !editingId) {
       resetForm();
    } else if (tab === 'LIST') {
      resetForm();
    }
  };

  const filteredGames = games.filter(g => 
    filterDifficulty === 'ALL' || (g.difficulty || DifficultyLevel.ALL_AGES) === filterDifficulty
  );

  const getDifficultyColor = (level?: DifficultyLevel) => {
    switch (level) {
      case DifficultyLevel.SENIOR: return 'bg-red-100 text-red-700 border-red-200';
      case DifficultyLevel.U16: return 'bg-orange-100 text-orange-700 border-orange-200';
      case DifficultyLevel.U12: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case DifficultyLevel.U9: return 'bg-lime-100 text-lime-700 border-lime-200';
      case DifficultyLevel.U7: return 'bg-green-100 text-green-700 border-green-200';
      case DifficultyLevel.U5: return 'bg-cyan-100 text-cyan-700 border-cyan-200';
      case DifficultyLevel.ALL_AGES: return 'bg-purple-100 text-purple-700 border-purple-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  if (loading && games.length === 0) {
    return <div className="p-10 text-center text-slate-400 font-bold animate-pulse">{t('common.loading')}</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Sub Nav */}
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto">
        <button
          onClick={() => handleTabChange('LIST')}
          className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'LIST' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <List size={18} /> {t('games.library')}
        </button>
        <button
          onClick={() => handleTabChange('CREATE')}
          className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'CREATE' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Plus size={18} /> {editingId ? t('common.edit') : t('games.create')}
        </button>
      </div>

      <div className="min-h-[500px]">
        {/* LIST VIEW */}
        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <h2 className="text-2xl font-black text-slate-800">{t('games.library')} ({filteredGames.length})</h2>

              <div className="flex items-center gap-2">
                <select
                  value={filterDifficulty}
                  onChange={(e) => setFilterDifficulty(e.target.value as DifficultyLevel | 'ALL')}
                  className="p-3 border border-slate-200 rounded-xl font-bold bg-white text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  <option value="ALL">Todas las edades</option>
                  {Object.values(DifficultyLevel).map(level => (
                    <option key={level} value={level}>{t(`diff.${level}`)}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredGames.length === 0 && (
                 <div className="col-span-full py-20 text-center text-slate-400 bg-white rounded-[2rem] border border-dashed border-slate-200">
                    <p className="font-bold">No hay ejercicios que mostrar.</p>
                 </div>
              )}
              {filteredGames.map(game => (
                <div key={game.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl transition group flex flex-col h-full relative overflow-hidden">
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex flex-wrap gap-2">
                      <span className="text-[9px] font-black uppercase bg-slate-100 text-slate-500 px-2 py-1 rounded">
                        {t(`cat.${game.category}`)}
                      </span>
                      <span className={`text-[9px] font-black uppercase px-2 py-1 rounded border ${getDifficultyColor(game.difficulty)}`}>
                        {t(`diff.${game.difficulty || DifficultyLevel.ALL_AGES}`)}
                      </span>
                    </div>
                  </div>

                  <h3 className="text-xl font-black text-slate-800 mb-2">{game.title}</h3>
                  <p className="text-slate-500 text-sm line-clamp-3 mb-6 flex-grow">{game.description}</p>

                  <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                    <div className="flex items-center gap-2 text-slate-400 font-bold text-xs uppercase">
                      <Clock size={14} /> {game.durationMin}m
                    </div>
                    <div className="flex gap-1">
                       <button onClick={() => setSelectedGame(game)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-blue-50 hover:text-blue-600 transition"><Eye size={16} /></button>
                       <button onClick={() => handleEdit(game)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition"><Pencil size={16} /></button>
                       <button onClick={() => handleDelete(game.id)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-rose-50 hover:text-rose-600 transition"><Trash2 size={16} /></button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* CREATE/EDIT VIEW */}
        {activeTab === 'CREATE' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">
               {/* BLOQUE AI PRO */}
              {!editingId && (
                <div className={`p-8 rounded-[2.5rem] border transition shadow-xl relative overflow-hidden
                  ${isPremium ? 'bg-gradient-to-r from-slate-900 to-indigo-900 border-indigo-500/20 text-white' : 'bg-white border-slate-100 shadow-sm'}`}>

                  {!isPremium && <div className="absolute top-4 right-8 bg-indigo-600 text-white text-[9px] font-black px-2 py-1 rounded uppercase flex items-center gap-1"><Lock size={10} /> PRO FEATURE</div>}

                  <div className="flex items-center gap-3 mb-4">
                    <div className={`p-3 rounded-2xl ${isPremium ? 'bg-indigo-500' : 'bg-slate-100 text-slate-400'}`}>
                       <Sparkles size={24} />
                    </div>
                    <div>
                       <h3 className={`text-xl font-black ${isPremium ? 'text-white' : 'text-slate-800'}`}>{t('games.ai.title')}</h3>
                       <p className={`text-sm ${isPremium ? 'text-indigo-200' : 'text-slate-400'}`}>{t('games.ai.desc')}</p>
                    </div>
                  </div>

                  <div className="flex flex-col sm:flex-row gap-3">
                    <input 
                      type="text" 
                      value={aiPrompt}
                      disabled={!isPremium}
                      onChange={(e) => setAiPrompt(e.target.value)}
                      placeholder={t('games.ai.placeholder')}
                      className={`flex-1 p-5 rounded-2xl outline-none border transition font-medium
                        ${isPremium 
                          ? 'bg-white/10 border-white/10 text-white placeholder-white/30 focus:bg-white/20' 
                          : 'bg-slate-50 border-slate-100 text-slate-300'}`}
                    />
                    <button 
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !aiPrompt || !isPremium}
                      className={`px-8 py-5 rounded-2xl font-black transition flex items-center justify-center gap-2 shadow-lg
                        ${isPremium 
                          ? 'bg-white text-indigo-600 hover:scale-105' 
                          : 'bg-slate-100 text-slate-300 cursor-not-allowed'}`}
                    >
                      {isGenerating ? t('games.ai.thinking') : t('games.ai.btn')}
                      {!isGenerating && <Sparkles size={18} />}
                    </button>
                  </div>
                  {!isPremium && <p className="mt-4 text-[10px] text-indigo-600 font-bold uppercase text-center tracking-widest animate-pulse">Suscríbete para desbloquear la Inteligencia Artificial</p>}
                </div>
              )}

              <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                <h2 className="text-2xl font-black text-slate-800">
                  {editingId ? t('common.edit') : t('games.create')}
                </h2>

                <form onSubmit={handleCreate} className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Título del Ejercicio</label>
                      <input required className="w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} />
                    </div>
                    <div>
