             <div>
                <h3 className="text-2xl font-black text-slate-900 mb-2">{t('pay.processing')}</h3>
                <p className="text-slate-400 font-bold text-xs uppercase tracking-widest">AIM Secure Payment Gateway</p>
             </div>
