import { Student, Game, Session, AttendanceRecord, DashboardStats, SportConfig, Group } from '../types';

const API_BASE_URL = '/api';

function getCookie(name: string): string | null {
  let cookieValue = null;
  if (typeof document !== 'undefined' && document.cookie && document.cookie !== '') {
    const cookies = document.cookie.split(';');
    for (let i = 0; i < cookies.length; i++) {
      const cookie = cookies[i].trim();
      if (cookie.substring(0, name.length + 1) === (name + '=')) {
        cookieValue = decodeURIComponent(cookie.substring(name.length + 1));
        break;
      }
    }
  }
  return cookieValue;
}

const apiRequest = async (endpoint: string, method: string = 'GET', body?: any) => {
  const headers: HeadersInit = {
    'Content-Type': 'application/json',
    'X-CSRFToken': getCookie('csrftoken') || '',
  };

  try {
    // We add a signal to fail fast since we know there's no real backend in this environment
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), 1000);

    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      method,
      headers,
      body: body ? JSON.stringify(body) : undefined,
      signal: controller.signal
    });

    clearTimeout(timeoutId);

    if (!response.ok) return fallbackToLocal(endpoint, method, body);
    return await response.json();
  } catch (error) {
    return fallbackToLocal(endpoint, method, body);
  }
};

/**
 * Robust fallback to LocalStorage.
 * It identifies the base resource (e.g., 'groups') to use a consistent key for all CRUD operations.
 */
const fallbackToLocal = (endpoint: string, method: string, body?: any) => {
  const parts = endpoint.split('/').filter(Boolean);
  if (parts.length === 0) return null;

  // The first part of the endpoint is our resource key (groups, students, etc.)
  const resource = parts[0];
  const storageKey = `aim_data_${resource}`;

  const data = localStorage.getItem(storageKey);
  const list = data ? JSON.parse(data) : [];

  if (method === 'GET') {
    // If it's a specific ID request (e.g., /groups/123/), return that item
    if (parts.length > 1 && resource !== 'stats') {
      const id = parts[1];
      return list.find((item: any) => item.id === id) || null;
    }
    return list;
  }

  if (method === 'POST') {
    const itemWithId = body.id ? body : { ...body, id: Date.now().toString() };
    const newList = [...list.filter((i: any) => i.id !== itemWithId.id), itemWithId];
    localStorage.setItem(storageKey, JSON.stringify(newList));
    return itemWithId;
  }

  if (method === 'DELETE') {
    const id = parts[parts.length - 1];
    const newList = list.filter((i: any) => i.id !== id);
    localStorage.setItem(storageKey, JSON.stringify(newList));
    return { success: true };
  }

  return null;
};

// GRUPOS
export const getGroups = (): Promise<Group[]> => apiRequest('/groups/');
export const addGroup = (group: Group) => apiRequest('/groups/', 'POST', group);
export const removeGroup = (id: string) => apiRequest(`/groups/${id}/`, 'DELETE');

// ALUMNOS
export const getStudents = (): Promise<Student[]> => apiRequest('/students/');
export const addStudent = (student: Student) => apiRequest('/students/', 'POST', student);
export const removeStudent = (id: string) => apiRequest(`/students/${id}/`, 'DELETE');

// JUEGOS Y SESIONES
export const getGames = (): Promise<Game[]> => apiRequest('/games/');
export const addGame = (game: Game) => apiRequest('/games/', 'POST', game);
export const removeGame = (id: string) => apiRequest(`/games/${id}/`, 'DELETE');

export const getSessions = (): Promise<Session[]> => apiRequest('/sessions/');
export const addSession = (session: Session) => apiRequest('/sessions/', 'POST', session);
export const removeSession = (id: string) => apiRequest(`/sessions/${id}/`, 'DELETE');

// ASISTENCIA
export const getAttendance = (): Promise<AttendanceRecord[]> => apiRequest('/attendance/');
export const saveAttendance = (record: AttendanceRecord) => apiRequest('/attendance/', 'POST', record);

export const getStats = async (): Promise<DashboardStats> => {
  const [students, groups, games, sessions] = await Promise.all([
    getStudents(),
    getGroups(),
    getGames(),
    getSessions()
  ]);

  return {
    totalStudents: students?.length || 0,
    totalGroups: groups?.length || 0,
    totalGames: games?.length || 0,
    sessionsThisMonth: sessions?.length || 0,
    averageAttendance: 85
  };
};

export const getSportConfig = (): SportConfig => {
  if (typeof localStorage === 'undefined') return { name: 'Fútbol', primaryColor: '#4f46e5', isPremium: false };
  const saved = localStorage.getItem('sport_config');
  return saved ? JSON.parse(saved) : { name: 'Fútbol', primaryColor: '#4f46e5', isPremium: false };
};

export const saveSportConfig = (config: SportConfig) => {
  localStorage.setItem('sport_config', JSON.stringify(config));
  window.dispatchEvent(new Event('storage_updated'));
};

