import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, ClipboardCheck, Trash2, CheckCircle, 
  X, FolderPlus, Layers, History, 
  UserPlus, ChevronRight, Search
} from 'lucide-react';
import { Student, AttendanceRecord, Group, DifficultyLevel } from '../types';
import * as storage from '../services/storage';
import { useLanguage } from '../LanguageContext';

const StudentsView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'GROUPS' | 'LIST' | 'ATTENDANCE' | 'HISTORY'>('GROUPS');
  const [students, setStudents] = useState<Student[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const { t } = useLanguage();

  const [selectedGroupId, setSelectedGroupId] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');

  const [showGroupModal, setShowGroupModal] = useState(false);
  const [showStudentModal, setShowStudentModal] = useState(false);

  const [studentForm, setStudentForm] = useState<Partial<Student>>({
    firstName: '', lastName: '', age: 0, position: '', groupId: '', emergencyContact: '', active: true
  });

  const [groupForm, setGroupForm] = useState<Partial<Group>>({
    name: '', description: '', level: DifficultyLevel.ALL_AGES
  });

  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [presentIds, setPresentIds] = useState<Set<string>>(new Set());
  const [attNotes, setAttNotes] = useState('');
  const [attendanceSaved, setAttendanceSaved] = useState(false);

  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setLoading(true);
    try {
      const [s, g, a] = await Promise.all([
        storage.getStudents(),
        storage.getGroups(),
        storage.getAttendance()
      ]);
      setStudents(s || []);
      setGroups(g || []);
      setAttendanceRecords(a || []);

      // If we don't have a selection but have groups, pick the first one
      if (g && g.length > 0 && !selectedGroupId) {
        setSelectedGroupId(g[0].id);
      }
    } catch (error) {
      console.error("Error loading data:", error);
    } finally {
      setLoading(false);
    }
  };

  const generateId = () => {
    return Date.now().toString(36) + Math.random().toString(36).substring(2);
  };

  const handleCreateGroup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupForm.name?.trim()) return;

    const newGroup: Group = {
      id: generateId(),
      name: groupForm.name.trim(),
      description: groupForm.description || '',
      level: groupForm.level || DifficultyLevel.ALL_AGES,
      createdAt: new Date().toISOString()
    };

    try {
      await storage.addGroup(newGroup);
      setGroupForm({ name: '', description: '', level: DifficultyLevel.ALL_AGES });
      setShowGroupModal(false);

      // Force immediate refresh
      const updatedGroups = await storage.getGroups();
      setGroups(updatedGroups || []);

      // Auto select the new group if it's the only one
      if (!selectedGroupId || updatedGroups.length === 1) {
        setSelectedGroupId(newGroup.id);
      }
    } catch (error) {
      alert("Error saving group. Please try again.");
    }
  };

  const handleRegisterStudent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studentForm.firstName || !studentForm.groupId) return;
    const newStudent: Student = {
      ...studentForm as Student,
      id: generateId(),
      active: true
    };
    await storage.addStudent(newStudent);
    setShowStudentModal(false);
    loadAllData();
  };

  const saveAttendance = async () => {
    if (!selectedGroupId) return;

    // Create attendance record
    const record: AttendanceRecord = {
      id: generateId(),
      date: attendanceDate,
      groupId: selectedGroupId,
      presentStudentIds: Array.from(presentIds),
      sessionNotes: attNotes
    };

    try {
      await storage.saveAttendance(record);
      setAttendanceSaved(true);
      setTimeout(() => setAttendanceSaved(false), 3000);
      loadAllData();
    } catch (error) {
      console.error("Error saving attendance:", error);
    }
  };

  const toggleAttendance = (studentId: string) => {
    const newPresentIds = new Set(presentIds);
    if (newPresentIds.has(studentId)) {
      newPresentIds.delete(studentId);
    } else {
      newPresentIds.add(studentId);
    }
    setPresentIds(newPresentIds);
  };

  const filteredStudents = students.filter(s => 
    s.groupId === selectedGroupId && 
    (s.firstName.toLowerCase().includes(searchTerm.toLowerCase()) || 
     s.lastName.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  if (loading && groups.length === 0) {
    return <div className="p-10 text-center text-slate-400 font-bold animate-pulse">{t('common.loading')}</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Sub Nav */}
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto">
        {(['GROUPS', 'LIST', 'ATTENDANCE', 'HISTORY'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === tab ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            {tab === 'GROUPS' && <Layers size={18} />}
            {tab === 'LIST' && <Users size={18} />}
            {tab === 'ATTENDANCE' && <ClipboardCheck size={18} />}
            {tab === 'HISTORY' && <History size={18} />}
            {t(`students.${tab.toLowerCase()}`)}
          </button>
        ))}
      </div>

      <div className="min-h-[500px]">
        {activeTab === 'GROUPS' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div>
                <h2 className="text-2xl font-black text-slate-800">{t('groups.title')}</h2>
                <p className="text-slate-500 font-medium">{t('groups.subtitle')}</p>
              </div>
              <button onClick={() => setShowGroupModal(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-indigo-700 transition shadow-lg shadow-indigo-100">
                <FolderPlus size={18} /> {t('groups.new')}
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {groups.map(group => (
                <button
                  key={group.id}
                  onClick={() => { setSelectedGroupId(group.id); setActiveTab('LIST'); }}
                  className={`p-8 rounded-[2.5rem] border text-left transition-all duration-300 group ${selectedGroupId === group.id ? 'bg-slate-900 border-slate-900 text-white shadow-2xl' : 'bg-white border-slate-100 hover:border-indigo-200 shadow-sm'}`}
                >
                  <div className="flex justify-between items-start mb-6">
                    <div className={`p-4 rounded-2xl transition-colors ${selectedGroupId === group.id ? 'bg-indigo-500/20 text-white' : 'bg-indigo-50 text-indigo-600'}`}>
                      <Users size={24} />
                    </div>
                    <span className={`text-[10px] font-black uppercase px-3 py-1.5 rounded-full ${selectedGroupId === group.id ? 'bg-white/10 text-white' : 'bg-slate-100 text-slate-500'}`}>
                      {t(`diff.${group.level}`)}
                    </span>
                  </div>
                  <h3 className="text-xl font-black mb-2">{group.name}</h3>
                  <p className={`text-sm line-clamp-2 font-medium ${selectedGroupId === group.id ? 'text-slate-400' : 'text-slate-500'}`}>{group.description}</p>

                  <div className="mt-8 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-60">
                    <ChevronRight size={14} /> Ver equipo
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                <select 
