import { Student, Game, Session, AttendanceRecord, DashboardStats, SportConfig, Group } from '../types';

// Helper to generate IDs consistently across the app
export const generateId = () => {
  return Date.now().toString(36) + Math.random().toString(36).substring(2);
};

const getLocalData = <T>(key: string): T[] => {
  if (typeof localStorage === 'undefined') return [];
  const data = localStorage.getItem(`aim_data_${key}`);
  return data ? JSON.parse(data) : [];
};

const saveLocalData = <T>(key: string, data: T[]) => {
  localStorage.setItem(`aim_data_${key}`, JSON.stringify(data));
  window.dispatchEvent(new Event('storage_updated'));
};

// GRUPOS
export const getGroups = async (): Promise<Group[]> => getLocalData<Group>('groups');
export const addGroup = async (group: Group): Promise<Group> => {
  const groups = getLocalData<Group>('groups');
  const newGroup = { ...group, id: group.id || generateId() };
  const updated = [...groups.filter(g => g.id !== newGroup.id), newGroup];
  saveLocalData('groups', updated);
  return newGroup;
};
export const removeGroup = async (id: string): Promise<void> => {
  const groups = getLocalData<Group>('groups');
  saveLocalData('groups', groups.filter(g => g.id !== id));
};

// ALUMNOS
export const getStudents = async (): Promise<Student[]> => getLocalData<Student>('students');
export const addStudent = async (student: Student): Promise<Student> => {
  const students = getLocalData<Student>('students');
  const newStudent = { ...student, id: student.id || generateId() };
  const updated = [...students.filter(s => s.id !== newStudent.id), newStudent];
  saveLocalData('students', updated);
  return newStudent;
};
export const removeStudent = async (id: string): Promise<void> => {
  const students = getLocalData<Student>('students');
  saveLocalData('students', students.filter(s => s.id !== id));
};

// JUEGOS
export const getGames = async (): Promise<Game[]> => getLocalData<Game>('games');
export const addGame = async (game: Game): Promise<Game> => {
  const games = getLocalData<Game>('games');
  const newGame = { ...game, id: game.id || generateId() };
  const updated = [...games.filter(g => g.id !== newGame.id), newGame];
  saveLocalData('games', updated);
  return newGame;
};
export const removeGame = async (id: string): Promise<void> => {
  const games = getLocalData<Game>('games');
  saveLocalData('games', games.filter(g => g.id !== id));
};

// SESIONES
export const getSessions = async (): Promise<Session[]> => getLocalData<Session>('sessions');
export const addSession = async (session: Session): Promise<Session> => {
  const sessions = getLocalData<Session>('sessions');
  const newSession = { ...session, id: session.id || generateId() };
  const updated = [...sessions.filter(s => s.id !== newSession.id), newSession];
  saveLocalData('sessions', updated);
  return newSession;
};
export const removeSession = async (id: string): Promise<void> => {
  const sessions = getLocalData<Session>('sessions');
  saveLocalData('sessions', sessions.filter(s => s.id !== id));
};

// ASISTENCIA
export const getAttendance = async (): Promise<AttendanceRecord[]> => getLocalData<AttendanceRecord>('attendance');
export const saveAttendance = async (record: AttendanceRecord): Promise<AttendanceRecord> => {
  const records = getLocalData<AttendanceRecord>('attendance');
  const newRecord = { ...record, id: record.id || generateId() };
  const updated = [...records, newRecord];
  saveLocalData('attendance', updated);
  return newRecord;
};

export const getStats = async (): Promise<DashboardStats> => {
  const [students, groups, games, sessions] = await Promise.all([
    getStudents(),
    getGroups(),
    getGames(),
    getSessions()
  ]);

  return {
    totalStudents: students.length,
    totalGroups: groups.length,
    totalGames: games.length,
    sessionsThisMonth: sessions.length,
    averageAttendance: 85
  };
};

export const getSportConfig = (): SportConfig => {
  if (typeof localStorage === 'undefined') return { name: 'Fútbol', primaryColor: '#4f46e5', isPremium: false };
  const saved = localStorage.getItem('sport_config');
  return saved ? JSON.parse(saved) : { name: 'Fútbol', primaryColor: '#4f46e5', isPremium: false };
};

export const saveSportConfig = (config: SportConfig) => {
  localStorage.setItem('sport_config', JSON.stringify(config));
  window.dispatchEvent(new Event('storage_updated'));
};

import React, { useState, useEffect } from 'react';
import { Plus, List, Sparkles, Trash2, Clock, BarChart, Pencil, Eye, X, Lock, Trophy } from 'lucide-react';
import { Game, SportCategory, DifficultyLevel } from '../types';
import * as storage from '../services/storage';
import { generateGameIdea } from '../services/geminiService';
import { useLanguage } from '../LanguageContext';

const GamesView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'CREATE' | 'LIST'>('LIST');
  const [games, setGames] = useState<Game[]>([]);
  const [filterDifficulty, setFilterDifficulty] = useState<DifficultyLevel | 'ALL'>('ALL');
  const [refresh, setRefresh] = useState(0);
  const [loading, setLoading] = useState(true);
  const [isPremium, setIsPremium] = useState(storage.getSportConfig().isPremium);
  const { t, language } = useLanguage();

  const [isGenerating, setIsGenerating] = useState(false);
  const [aiPrompt, setAiPrompt] = useState('');

  const [editingId, setEditingId] = useState<string | null>(null);
  const [formData, setFormData] = useState<Partial<Game>>({
    title: '',
    description: '',
    category: SportCategory.GENERAL,
    difficulty: DifficultyLevel.ALL_AGES,
    durationMin: 15,
    tags: []
  });

  const [selectedGame, setSelectedGame] = useState<Game | null>(null);

  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const data = await storage.getGames();
        setGames(data);
        setIsPremium(storage.getSportConfig().isPremium);
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    loadData();

    const handleStorageUpdate = () => setIsPremium(storage.getSportConfig().isPremium);
    window.addEventListener('storage_updated', handleStorageUpdate);
    return () => window.removeEventListener('storage_updated', handleStorageUpdate);
  }, [refresh]);

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.title) return;

    const newGame: Game = {
      id: editingId || storage.generateId(), 
      title: formData.title!,
      description: formData.description || '',
      category: formData.category || SportCategory.GENERAL,
      difficulty: formData.difficulty || DifficultyLevel.ALL_AGES,
      durationMin: formData.durationMin || 15,
      tags: formData.tags || []
    };

    await storage.addGame(newGame);
    resetForm();
    setRefresh(r => r + 1);
    setActiveTab('LIST');
  };

  const resetForm = () => {
    setEditingId(null);
    setFormData({
      title: '',
      description: '',
      category: SportCategory.GENERAL,
      difficulty: DifficultyLevel.ALL_AGES,
      durationMin: 15,
      tags: []
    });
  };

  const handleGenerateAI = async () => {
    if (!isPremium) {
       alert(t('premium.locked') + ": " + t('premium.desc'));
       return;
    }
    if (!aiPrompt) return;
    setIsGenerating(true);
    try {
      const suggestion = await generateGameIdea(aiPrompt, language);
      setFormData({
        ...formData,
        title: suggestion.title,
        description: suggestion.description,
        category: suggestion.category,
        difficulty: suggestion.difficulty,
        durationMin: suggestion.durationMin,
      });
    } catch (error) {
      alert("Failed to generate game. Please check your API Key.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleEdit = (game: Game) => {
    setEditingId(game.id);
    setFormData({
      title: game.title,
      description: game.description,
      category: game.category,
      difficulty: game.difficulty,
      durationMin: game.durationMin,
      tags: game.tags
    });
    setActiveTab('CREATE');
  };

  const handleDelete = async (id: string) => {
    if(confirm('¿Seguro que quieres eliminar este ejercicio?')) {
      await storage.removeGame(id);
      setRefresh(r => r + 1);
    }
  }

  const handleTabChange = (tab: 'CREATE' | 'LIST') => {
    setActiveTab(tab);
    if (tab === 'CREATE' && !editingId) {
       resetForm();
    } else if (tab === 'LIST') {
      resetForm();
    }
  };

  const filteredGames = games.filter(g => 
    filterDifficulty === 'ALL' || (g.difficulty || DifficultyLevel.ALL_AGES) === filterDifficulty
  );

  const getDifficultyColor = (level?: DifficultyLevel) => {
    switch (level) {
      case DifficultyLevel.SENIOR: return 'bg-red-100 text-red-700 border-red-200';
      case DifficultyLevel.U16: return 'bg-orange-100 text-orange-700 border-orange-200';
      case DifficultyLevel.U12: return 'bg-yellow-100 text-yellow-700 border-yellow-200';
      case DifficultyLevel.U9: return 'bg-lime-100 text-lime-700 border-lime-200';
      case DifficultyLevel.U7: return 'bg-green-100 text-green-700 border-green-200';
      case DifficultyLevel.U5: return 'bg-cyan-100 text-cyan-700 border-cyan-200';
      case DifficultyLevel.ALL_AGES: return 'bg-purple-100 text-purple-700 border-purple-200';
      default: return 'bg-gray-100 text-gray-700 border-gray-200';
    }
  };

  if (loading && games.length === 0) {
    return <div className="p-10 text-center text-slate-400 font-bold animate-pulse">{t('common.loading')}</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto">
        <button
          onClick={() => handleTabChange('LIST')}
          className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'LIST' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <List size={18} /> {t('games.library')}
        </button>
        <button
          onClick={() => handleTabChange('CREATE')}
          className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'CREATE' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Plus size={18} /> {editingId ? t('common.edit') : t('games.create')}
        </button>
      </div>

      <div className="min-h-[500px]">
        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <h2 className="text-2xl font-black text-slate-800">{t('games.library')} ({filteredGames.length})</h2>
              <div className="flex items-center gap-2">
                <select
                  value={filterDifficulty}
                  onChange={(e) => setFilterDifficulty(e.target.value as DifficultyLevel | 'ALL')}
                  className="p-3 border border-slate-200 rounded-xl font-bold bg-white text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  <option value="ALL">Todas las edades</option>
                  {Object.values(DifficultyLevel).map(level => (
                    <option key={level} value={level}>{t(`diff.${level}`)}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {filteredGames.length === 0 && (
                 <div className="col-span-full py-20 text-center text-slate-400 bg-white rounded-[2rem] border border-dashed border-slate-200">
                    <p className="font-bold">No hay ejercicios que mostrar.</p>
                 </div>
              )}
              {filteredGames.map(game => (
                <div key={game.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl transition group flex flex-col h-full relative overflow-hidden">
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex flex-wrap gap-2">
                      <span className="text-[9px] font-black uppercase bg-slate-100 text-slate-500 px-2 py-1 rounded">
                        {t(`cat.${game.category}`)}
                      </span>
                      <span className={`text-[9px] font-black uppercase px-2 py-1 rounded border ${getDifficultyColor(game.difficulty)}`}>
                        {t(`diff.${game.difficulty || DifficultyLevel.ALL_AGES}`)}
                      </span>
                    </div>
                  </div>
                  <h3 className="text-xl font-black text-slate-800 mb-2">{game.title}</h3>
                  <p className="text-slate-500 text-sm line-clamp-3 mb-6 flex-grow">{game.description}</p>
                  <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                    <div className="flex items-center gap-2 text-slate-400 font-bold text-xs uppercase">
                      <Clock size={14} /> {game.durationMin}m
                    </div>
                    <div className="flex gap-1">
                       <button onClick={() => setSelectedGame(game)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-blue-50 hover:text-blue-600 transition"><Eye size={16} /></button>
                       <button onClick={() => handleEdit(game)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-indigo-50 hover:text-indigo-600 transition"><Pencil size={16} /></button>
                       <button onClick={() => handleDelete(game.id)} className="p-2 bg-slate-50 text-slate-400 rounded-xl hover:bg-rose-50 hover:text-rose-600 transition"><Trash2 size={16} /></button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'CREATE' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">
              {!editingId && (
                <div className={`p-8 rounded-[2.5rem] border transition shadow-xl relative overflow-hidden
                  ${isPremium ? 'bg-gradient-to-r from-slate-900 to-indigo-900 border-indigo-500/20 text-white' : 'bg-white border-slate-100 shadow-sm'}`}>
                  {!isPremium && <div className="absolute top-4 right-8 bg-indigo-600 text-white text-[9px] font-black px-2 py-1 rounded uppercase flex items-center gap-1"><Lock size={10} /> PRO FEATURE</div>}
                  <div className="flex items-center gap-3 mb-4">
                    <div className={`p-3 rounded-2xl ${isPremium ? 'bg-indigo-500' : 'bg-slate-100 text-slate-400'}`}>
                       <Sparkles size={24} />
                    </div>
                    <div>
                       <h3 className={`text-xl font-black ${isPremium ? 'text-white' : 'text-slate-800'}`}>{t('games.ai.title')}</h3>
                       <p className={`text-sm ${isPremium ? 'text-indigo-200' : 'text-slate-400'}`}>{t('games.ai.desc')}</p>
                    </div>
                  </div>
                  <div className="flex flex-col sm:flex-row gap-3">
                    <input 
                      type="text" 
                      value={aiPrompt}
                      disabled={!isPremium}
                      onChange={(e) => setAiPrompt(e.target.value)}
                      placeholder={t('games.ai.placeholder')}
                      className={`flex-1 p-5 rounded-2xl outline-none border transition font-medium
                        ${isPremium 
                          ? 'bg-white/10 border-white/10 text-white placeholder-white/30 focus:bg-white/20' 
                          : 'bg-slate-50 border-slate-100 text-slate-300'}`}
                    />
                    <button 
                      onClick={handleGenerateAI}
                      disabled={isGenerating || !aiPrompt || !isPremium}
                      className={`px-8 py-5 rounded-2xl font-black transition flex items-center justify-center gap-2 shadow-lg
                        ${isPremium 
                          ? 'bg-white text-indigo-600 hover:scale-105' 
                          : 'bg-slate-100 text-slate-300 cursor-not-allowed'}`}
                    >
                      {isGenerating ? t('games.ai.thinking') : t('games.ai.btn')}
                      {!isGenerating && <Sparkles size={18} />}
                    </button>
                  </div>
                </div>
              )}
              <div className="bg-white p-8 rounded-[2.5rem] border shadow-sm space-y-6">
                <h2 className="text-2xl font-black text-slate-800">
                  {editingId ? t('common.edit') : t('games.create')}
                </h2>
                <form onSubmit={handleCreate} className="space-y-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Título del Ejercicio</label>
                      <input required className="w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" value={formData.title} onChange={e => setFormData({ ...formData, title: e.target.value })} />
                    </div>
                    <div>
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Duración (min)</label>
                      <input type="number" className="w-full p-4 bg-slate-50 border rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-indigo-600" value={formData.durationMin} onChange={e => setFormData({ ...formData, durationMin: parseInt(e.target.value) })} />
                    </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Categoría</label>
                      <select className="w-full p-4 bg-slate-50 border rounded-2xl outline-none font-bold" value={formData.category} onChange={e => setFormData({ ...formData, category: e.target.value as SportCategory })}>
                        {Object.values(SportCategory).map(cat => (
                          <option key={cat} value={cat}>{t(`cat.${cat}`)}</option>
                        ))}
                      </select>
                    </div>
                    <div>
                      <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Edad / Nivel</label>
                      <select className="w-full p-4 bg-slate-50 border rounded-2xl outline-none font-bold" value={formData.difficulty} onChange={e => setFormData({ ...formData, difficulty: e.target.value as DifficultyLevel })}>
                        {Object.values(DifficultyLevel).map(diff => (
                          <option key={diff} value={diff}>{t(`diff.${diff}`)}</option>
                        ))}
                      </select>
                    </div>
                  </div>
                  <div>
                    <label className="text-[10px] font-black uppercase text-slate-400 ml-1">Descripción y Reglas</label>
                    <textarea required className="w-full p-4 bg-slate-50 border rounded-2xl outline-none h-40 font-medium" value={formData.description} onChange={e => setFormData({ ...formData, description: e.target.value })} />
                  </div>
                  <div className="pt-4 flex gap-3">
                    {editingId && (
                      <button type="button" onClick={resetForm} className="flex-1 bg-slate-100 text-slate-500 py-5 rounded-2xl font-black hover:bg-slate-200 transition">
                        {t('common.cancel')}
                      </button>
                    )}
                    <button type="submit" className="flex-[2] bg-slate-900 text-white py-5 rounded-2xl font-black text-lg hover:bg-slate-800 transition shadow-xl">
                      {editingId ? t('common.update') : 'Guardar Ejercicio'}
                    </button>
                  </div>
                </form>
              </div>
            </div>
            <div className="hidden lg:block space-y-6 text-center p-10 bg-indigo-50 rounded-[3rem] border border-indigo-100">
               <Trophy size={64} className="mx-auto text-indigo-600 mb-4" />
               <h4 className="text-xl font-black text-indigo-900 italic">"Los grandes entrenadores nunca dejan de aprender ejercicios."</h4>
            </div>
          </div>
        )}
      </div>
      {selectedGame && (
        <div className="fixed inset-0 bg-slate-900/60 z-[100] flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-[3rem] max-w-2xl w-full max-h-[90vh] overflow-hidden flex flex-col shadow-2xl border border-slate-100">
            <div className="p-10 border-b border-slate-50 flex justify-between items-start sticky top-0 bg-white z-10">
              <div>
                <div className="flex gap-2 mb-3">
                   <span className="text-[10px] font-black uppercase tracking-widest bg-slate-100 px-2 py-1 rounded text-slate-500">{t(`cat.${selectedGame.category}`)}</span>
                   <span className={`text-[10px] font-black uppercase tracking-widest px-2 py-1 rounded border ${getDifficultyColor(selectedGame.difficulty)}`}>{t(`diff.${selectedGame.difficulty || DifficultyLevel.ALL_AGES}`)}</span>
                </div>
                <h2 className="text-3xl font-black text-slate-900">{selectedGame.title}</h2>
              </div>
              <button onClick={() => setSelectedGame(null)} className="p-3 bg-slate-50 rounded-full hover:bg-rose-50 hover:text-rose-500 transition"><X size={24} /></button>
            </div>
            <div className="p-10 overflow-y-auto space-y-8">
              <div className="flex items-center gap-2 text-indigo-600 font-black text-xs uppercase tracking-[0.2em]"><Clock size={16} /> {selectedGame.durationMin} minutos</div>
              <div className="space-y-4">
                 <h3 className="text-[10px] font-black uppercase text-slate-400 tracking-[0.3em]">Instrucciones y Desarrollo</h3>
                 <div className="text-slate-700 leading-relaxed font-medium bg-slate-50 p-8 rounded-[2rem] border border-slate-100 whitespace-pre-wrap">{selectedGame.description}</div>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default GamesView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Calendar, Trash2, Clock, PlayCircle, 
  Pencil, Eye, X, Layout, Target, ChevronRight,
  Info, ArrowLeft
} from 'lucide-react';
import { Session, Game, SessionItem, DifficultyLevel, Group } from '../types';
import * as storage from '../services/storage';
import { useLanguage } from '../LanguageContext';

const SessionsView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'CREATE' | 'LIST'>('LIST');
  const [sessions, setSessions] = useState<Session[]>([]);
  const [games, setGames] = useState<Game[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [loading, setLoading] = useState(true);
  const { t } = useLanguage();

  const [editingId, setEditingId] = useState<string | null>(null);
  const [sessionTitle, setSessionTitle] = useState('');
  const [selectedGroupId, setSelectedGroupId] = useState('');
  const [sessionDate, setSessionDate] = useState(new Date().toISOString().split('T')[0]);
  const [sessionDescription, setSessionDescription] = useState('');
  const [selectedItems, setSelectedItems] = useState<SessionItem[]>([]);

  const [selectedSession, setSelectedSession] = useState<Session | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setLoading(true);
    const [sessionsData, gamesData, groupsData] = await Promise.all([
      storage.getSessions(),
      storage.getGames(),
      storage.getGroups()
    ]);
    setSessions(sessionsData);
    setGames(gamesData);
    setGroups(groupsData);
    if (groupsData.length > 0 && !selectedGroupId) setSelectedGroupId(groupsData[0].id);
    setLoading(false);
  };

  const addGameToSession = (game: Game) => {
    setSelectedItems(prev => [
      ...prev,
      { gameId: game.id, durationMin: game.durationMin }
    ]);
  };

  const removeGameFromSession = (index: number) => {
    const newItems = [...selectedItems];
    newItems.splice(index, 1);
    setSelectedItems(newItems);
  };

  const updateItemDuration = (index: number, minutes: number) => {
    const newItems = [...selectedItems];
    newItems[index].durationMin = minutes;
    setSelectedItems(newItems);
  };

  const calculateTotalDuration = (items: SessionItem[]) => {
    return items.reduce((acc, curr) => acc + curr.durationMin, 0);
  };

  const handleCreate = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sessionTitle || !selectedGroupId) return;

    const newSession: Session = {
      id: editingId || storage.generateId(),
      groupId: selectedGroupId,
      title: sessionTitle,
      date: sessionDate,
      description: sessionDescription,
      items: selectedItems,
      totalDuration: calculateTotalDuration(selectedItems)
    };

    await storage.addSession(newSession);
    resetForm();
    loadData();
    setActiveTab('LIST');
  };

  const resetForm = () => {
    setEditingId(null);
    setSessionTitle('');
    setSessionDescription('');
    setSessionDate(new Date().toISOString().split('T')[0]);
    setSelectedItems([]);
  };

  const handleEdit = (session: Session) => {
    setEditingId(session.id);
    setSessionTitle(session.title);
    setSelectedGroupId(session.groupId);
    setSessionDescription(session.description || '');
    setSessionDate(session.date);
    setSelectedItems(session.items);
    setActiveTab('CREATE');
  };

  if (loading) return <div className="p-10 text-center animate-pulse font-bold text-slate-400">...</div>;

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200">
        <button
          onClick={() => setActiveTab('LIST')}
          className={`flex-1 px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'LIST' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Calendar size={18} /> {t('sessions.history')}
        </button>
        <button
          onClick={() => { setActiveTab('CREATE'); if(!editingId) resetForm(); }}
          className={`flex-1 px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === 'CREATE' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
        >
          <Plus size={18} /> {editingId ? t('common.edit') : t('sessions.create')}
        </button>
      </div>

      <div className="min-h-[600px]">
        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-black text-slate-800">{t('sessions.title')}</h2>
            <div className="grid grid-cols-1 gap-4">
              {sessions.length === 0 && (
                <div className="py-20 text-center text-slate-400 bg-white rounded-[2rem] border border-dashed border-slate-200">
                  <p className="font-bold">{t('sessions.empty')}</p>
                </div>
              )}
              {sessions.slice().reverse().map(session => {
                const group = groups.find(g => g.id === session.groupId);
                return (
                  <div key={session.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-xl transition group flex flex-col md:flex-row items-center gap-6">
                    <div className="w-20 h-20 bg-slate-50 rounded-3xl flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                      <span className="text-sm font-black uppercase">{new Date(session.date).toLocaleString('default', { month: 'short' })}</span>
                      <span className="text-2xl font-black">{session.date.split('-')[2]}</span>
                    </div>
                    <div className="flex-1 text-center md:text-left">
                      <div className="flex flex-wrap justify-center md:justify-start gap-2 mb-2">
                        <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[10px] font-black uppercase rounded">{group?.name || '---'}</span>
                        <span className="px-2 py-0.5 bg-slate-100 text-slate-500 text-[10px] font-black uppercase rounded">{session.totalDuration} min</span>
                      </div>
                      <h3 className="text-xl font-black text-slate-800">{session.title}</h3>
                    </div>
                    <div className="flex gap-2">
                      <button onClick={() => setSelectedSession(session)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-blue-50 hover:text-blue-600 transition"><Eye size={20} /></button>
                      <button onClick={() => handleEdit(session)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-indigo-50 hover:text-indigo-600 transition"><Pencil size={20} /></button>
                      <button onClick={() => storage.removeSession(session.id).then(loadData)} className="p-3 bg-slate-50 text-slate-400 rounded-2xl hover:bg-rose-50 hover:text-rose-600 transition"><Trash2 size={20} /></button>
                    </div>
                  </div>
                );
              })}
            </div>
          </div>
        )}

        {activeTab === 'CREATE' && (
          <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
            <div className="lg:col-span-2 space-y-6">
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
                <h2 className="text-2xl font-black text-slate-800">{editingId ? t('common.edit') : t('sessions.create')}</h2>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">{t('sessions.form.title')}</label>
                    <input type="text" value={sessionTitle} onChange={e => setSessionTitle(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" placeholder="..." />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">{t('sessions.form.group')}</label>
                    <select value={selectedGroupId} onChange={e => setSelectedGroupId(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-indigo-600">
                      {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                    </select>
                  </div>
                </div>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">{t('sessions.form.date')}</label>
                    <input type="date" value={sessionDate} onChange={e => setSessionDate(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">Total</label>
                    <div className="w-full p-4 bg-indigo-50 border border-indigo-100 rounded-2xl font-black text-indigo-600">{calculateTotalDuration(selectedItems)} min</div>
                  </div>
                </div>
                <div className="space-y-1">
                   <label className="text-[10px] font-black uppercase tracking-widest text-slate-400 ml-1">{t('sessions.form.desc')}</label>
                   <textarea value={sessionDescription} onChange={e => setSessionDescription(e.target.value)} className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 h-24" />
                </div>
              </div>
              <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm min-h-[300px]">
                <h3 className="text-xl font-black text-slate-800 mb-6 flex items-center gap-2"><Target className="text-indigo-600" /> {t('sessions.timeline')}</h3>
                <div className="space-y-4">
                  {selectedItems.map((item, idx) => {
                    const game = games.find(g => g.id === item.gameId);
                    return (
                      <div key={idx} className="bg-slate-50 p-4 rounded-3xl border border-slate-100 flex items-center gap-4">
                        <div className="bg-white text-indigo-600 w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-sm shrink-0">{idx+1}</div>
                        <div className="flex-1 font-bold text-slate-800">{game?.title || 'Game Deleted'}</div>
                        <input type="number" value={item.durationMin} onChange={(e) => updateItemDuration(idx, parseInt(e.target.value))} className="w-16 p-2 bg-white border border-slate-100 rounded-xl text-center font-bold text-indigo-600" />
                        <button onClick={() => removeGameFromSession(idx)} className="p-2 text-slate-300 hover:text-rose-500 transition"><Trash2 size={18} /></button>
                      </div>
                    );
                  })}
                </div>
                <div className="mt-8 pt-6 border-t border-slate-50">
                  <button onClick={handleCreate} disabled={!sessionTitle} className="w-full bg-slate-900 text-white py-5 rounded-[1.5rem] font-black text-lg hover:bg-slate-800 transition disabled:opacity-20">{t('sessions.save_btn')}</button>
                </div>
              </div>
            </div>
            <div className="space-y-6">
              <div className="bg-indigo-600 p-8 rounded-[2.5rem] shadow-xl text-white h-fit">
                <h3 className="text-xl font-black mb-4">{t('sessions.library')}</h3>
                <div className="space-y-3 max-h-[600px] overflow-y-auto pr-2 custom-scrollbar">
                  {games.map(game => (
                    <div key={game.id} className="p-4 bg-white/10 border border-white/10 rounded-2xl hover:bg-white hover:text-indigo-600 transition cursor-pointer group flex justify-between items-center" onClick={() => addGameToSession(game)}>
                      <div><div className="font-bold text-sm">{game.title}</div><div className="text-[9px] opacity-60 uppercase">{game.durationMin} min</div></div>
                      <Plus size={16} />
                    </div>
                  ))}
                </div>
              </div>
            </div>
          </div>
        )}
      </div>

       {selectedSession && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4 animate-fade-in">
          <div className="bg-white rounded-[3rem] max-w-2xl w-full max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
            <div className="p-10 bg-slate-900 text-white relative">
              <button onClick={() => setSelectedSession(null)} className="absolute top-8 right-8 p-2 bg-white/10 rounded-full"><X size={24} /></button>
              <h2 className="text-3xl font-black">{selectedSession.title}</h2>
              <p className="text-slate-400 mt-2 font-medium">{new Date(selectedSession.date).toLocaleDateString()}</p>
            </div>
            <div className="flex-1 overflow-y-auto p-10 space-y-8">
              <div className="space-y-3">
                 <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">{t('sessions.form.desc')}</h3>
                 <p className="text-slate-600 bg-slate-50 p-6 rounded-3xl border border-slate-100">{selectedSession.description}</p>
              </div>
              <div className="space-y-4">
                <h3 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400">{t('sessions.timeline')}</h3>
                {selectedSession.items.map((item, idx) => {
                  const game = games.find(g => g.id === item.gameId);
                  return (
                    <div key={idx} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm flex items-start gap-4">
                       <div className="bg-indigo-50 text-indigo-600 w-12 h-12 rounded-2xl flex items-center justify-center font-black shrink-0">{idx + 1}</div>
                       <div className="flex-1">
                         <h4 className="font-black text-slate-800 text-lg">{game?.title || 'Deleted Drill'}</h4>
                         <div className="text-[9px] font-black text-slate-400 uppercase">{item.durationMin} min</div>
                       </div>
                    </div>
                  )
                })}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default SessionsView;

import React, { useState, useEffect } from 'react';
import { 
  Plus, Users, ClipboardCheck, Trash2, CheckCircle, 
  X, FolderPlus, Layers, History, 
  UserPlus, ChevronRight, Search, Clock, Calendar, FileText,
  UserCheck, UserX
} from 'lucide-react';
import { Student, AttendanceRecord, Group, DifficultyLevel } from '../types';
import * as storage from '../services/storage';
import { useLanguage } from '../LanguageContext';

const StudentsView: React.FC = () => {
  const [activeTab, setActiveTab] = useState<'GROUPS' | 'LIST' | 'ATTENDANCE' | 'HISTORY'>('GROUPS');
  const [students, setStudents] = useState<Student[]>([]);
  const [groups, setGroups] = useState<Group[]>([]);
  const [attendanceRecords, setAttendanceRecords] = useState<AttendanceRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const { t } = useLanguage();

  const [selectedGroupId, setSelectedGroupId] = useState<string>('');
  const [searchTerm, setSearchTerm] = useState('');

  const [showGroupModal, setShowGroupModal] = useState(false);
  const [showStudentModal, setShowStudentModal] = useState(false);

  // Modales de detalle
  const [selectedRecordDetails, setSelectedRecordDetails] = useState<AttendanceRecord | null>(null);
  const [selectedStudentHistory, setSelectedStudentHistory] = useState<Student | null>(null);

  const [studentForm, setStudentForm] = useState<Partial<Student>>({
    firstName: '', lastName: '', age: 0, position: '', groupId: '', emergencyContact: '', active: true
  });

  const [groupForm, setGroupForm] = useState<Partial<Group>>({
    name: '', description: '', level: DifficultyLevel.ALL_AGES
  });

  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [presentIds, setPresentIds] = useState<Set<string>>(new Set());
  const [attNotes, setAttNotes] = useState('');
  const [attendanceSaved, setAttendanceSaved] = useState(false);

  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setLoading(true);
    try {
      const [s, g, a] = await Promise.all([
        storage.getStudents(),
        storage.getGroups(),
        storage.getAttendance()
      ]);
      setStudents(s || []);
      setGroups(g || []);
      setAttendanceRecords(a || []);

      if (g && g.length > 0 && !selectedGroupId) {
        setSelectedGroupId(g[0].id);
      }
    } catch (error) {
      console.error("Error loading data:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateGroup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupForm.name?.trim()) return;

    const newGroup: Group = {
      id: storage.generateId(),
      name: groupForm.name.trim(),
      description: groupForm.description || '',
      level: groupForm.level || DifficultyLevel.ALL_AGES,
      createdAt: new Date().toISOString()
    };

    try {
      await storage.addGroup(newGroup);
      setGroupForm({ name: '', description: '', level: DifficultyLevel.ALL_AGES });
      setShowGroupModal(false);
      loadAllData();
    } catch (error) {
      alert("Error saving group.");
    }
  };

  const handleRegisterStudent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studentForm.firstName || !studentForm.groupId) return;
    const newStudent: Student = {
      ...studentForm as Student,
      id: storage.generateId(),
      active: true
    };
    await storage.addStudent(newStudent);
    setShowStudentModal(false);
    loadAllData();
  };

  const saveAttendance = async () => {
    if (!selectedGroupId) return;

    const record: AttendanceRecord = {
      id: storage.generateId(),
      date: attendanceDate,
      groupId: selectedGroupId,
      presentStudentIds: Array.from(presentIds),
      sessionNotes: attNotes
    };

    try {
      await storage.saveAttendance(record);
      setAttendanceSaved(true);
      setTimeout(() => setAttendanceSaved(false), 3000);
      loadAllData();
    } catch (error) {
      console.error("Error saving attendance:", error);
    }
  };

  const toggleAttendance = (studentId: string) => {
    const newPresentIds = new Set(presentIds);
    if (newPresentIds.has(studentId)) {
      newPresentIds.delete(studentId);
    } else {
      newPresentIds.add(studentId);
    }
    setPresentIds(newPresentIds);
  };

  const filteredStudents = students.filter(s => 
    s.groupId === selectedGroupId && 
    (s.firstName.toLowerCase().includes(searchTerm.toLowerCase()) || 
     s.lastName.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  if (loading && groups.length === 0) {
    return <div className="p-10 text-center text-slate-400 font-bold animate-pulse">{t('common.loading')}</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Sub Nav */}
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto">
        {(['GROUPS', 'LIST', 'ATTENDANCE', 'HISTORY'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === tab ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            {tab === 'GROUPS' && <Layers size={18} />}
            {tab === 'LIST' && <Users size={18} />}
            {tab === 'ATTENDANCE' && <ClipboardCheck size={18} />}
            {tab === 'HISTORY' && <History size={18} />}
            {t(`students.${tab.toLowerCase()}`)}
          </button>
        ))}
      </div>

      <div className="min-h-[500px]">
        {activeTab === 'GROUPS' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div>
                <h2 className="text-2xl font-black text-slate-800">{t('groups.title')}</h2>
                <p className="text-slate-500 font-medium">{t('groups.subtitle')}</p>
              </div>
              <button onClick={() => setShowGroupModal(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-indigo-700 transition shadow-lg shadow-indigo-100">
                <FolderPlus size={18} /> {t('groups.new')}
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {groups.map(group => (
                <button
                  key={group.id}
                  onClick={() => { setSelectedGroupId(group.id); setActiveTab('LIST'); }}
                  className={`p-8 rounded-[2.5rem] border text-left transition-all duration-300 group ${selectedGroupId === group.id ? 'bg-slate-900 border-slate-900 text-white shadow-2xl' : 'bg-white border-slate-100 hover:border-indigo-200 shadow-sm'}`}
                >
                  <div className="flex justify-between items-start mb-6">
                    <div className={`p-4 rounded-2xl transition-colors ${selectedGroupId === group.id ? 'bg-indigo-500/20 text-white' : 'bg-indigo-50 text-indigo-600'}`}>
                      <Users size={24} />
                    </div>
                    <span className={`text-[10px] font-black uppercase px-3 py-1.5 rounded-full ${selectedGroupId === group.id ? 'bg-white/10 text-white' : 'bg-slate-100 text-slate-500'}`}>
                      {t(`diff.${group.level}`)}
                    </span>
                  </div>
                  <h3 className="text-xl font-black mb-2">{group.name}</h3>
                  <p className={`text-sm line-clamp-2 font-medium ${selectedGroupId === group.id ? 'text-slate-400' : 'text-slate-500'}`}>{group.description}</p>

                  <div className="mt-8 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-60">
                    <ChevronRight size={14} /> Ver equipo
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                <select 
                  value={selectedGroupId} 
                  onChange={(e) => setSelectedGroupId(e.target.value)}
                  className="bg-white border border-slate-200 px-4 py-3 rounded-xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
                <h2 className="text-2xl font-black text-slate-800">{t('students.list')}</h2>
              </div>
              <div className="flex items-center gap-2">
                <div className="relative">
                  <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder={t('groups.search_ph')}
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium text-sm"
                  />
                </div>
                <button onClick={() => setShowStudentModal(true)} className="bg-slate-900 text-white px-5 py-3 rounded-xl font-black flex items-center gap-2 hover:bg-slate-800 transition">
                  <UserPlus size={18} /> {t('students.new_btn')}
                </button>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-50 border-b border-slate-100">
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">{t('students.table.student')}</th>
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">{t('students.table.position')}</th>
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">{t('students.table.contact')}</th>
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400 text-right">{t('students.table.actions')}</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredStudents.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-8 py-20 text-center text-slate-400 font-bold">
                          {t('students.table.empty')}
                        </td>
                      </tr>
                    )}
                    {filteredStudents.map(student => (
                      <tr key={student.id} className="hover:bg-slate-50 transition-colors group">
                        <td className="px-8 py-5">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center font-black">
                              {student.firstName[0]}{student.lastName[0]}
                            </div>
                            <div>
                              <div className="font-bold text-slate-800">{student.firstName} {student.lastName}</div>
                              <div className="text-[10px] text-slate-400 font-black uppercase">{student.age} {t('modal.student.age')}</div>
                            </div>
                          </div>
                        </td>
                        <td className="px-8 py-5">
                          <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-bold uppercase tracking-wider">{student.position}</span>
                        </td>
                        <td className="px-8 py-5">
                          <div className="text-sm font-medium text-slate-600">{student.emergencyContact}</div>
                        </td>
                        <td className="px-8 py-5 text-right">
                          <div className="flex items-center justify-end gap-2">
                             <button onClick={() => setSelectedStudentHistory(student)} className="p-2 text-slate-300 hover:text-indigo-600 transition-colors">
                               <Clock size={18} />
                             </button>
                             <button onClick={() => storage.removeStudent(student.id).then(loadAllData)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors">
                               <Trash2 size={18} />
                             </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'ATTENDANCE' && (
          <div className="space-y-6 max-w-4xl mx-auto">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                  <h2 className="text-2xl font-black text-slate-800">{t('students.att.title')}</h2>
                  <p className="text-slate-500 font-medium">{t('students.att.desc')}</p>
                </div>
                <input 
                  type="date" 
                  value={attendanceDate}
                  onChange={(e) => setAttendanceDate(e.target.value)}
                  className="px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-indigo-600"
                />
              </div>

              <div className="space-y-4">
                {filteredStudents.length === 0 && (
                  <div className="py-12 text-center text-slate-400 font-bold bg-slate-50 rounded-3xl border border-dashed border-slate-200">
                    {t('students.att.no_students')}
                  </div>
                )}
                {filteredStudents.map(student => (
                  <div 
                    key={student.id} 
                    onClick={() => toggleAttendance(student.id)}
                    className={`flex items-center justify-between p-4 rounded-2xl border cursor-pointer transition-all ${presentIds.has(student.id) ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}
                  >
                    <div className="flex items-center gap-4">
                      <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${presentIds.has(student.id) ? 'bg-emerald-500 border-emerald-500 text-white' : 'border-slate-200'}`}>
                        {presentIds.has(student.id) && <CheckCircle size={14} />}
                      </div>
                      <span className={`font-bold ${presentIds.has(student.id) ? 'text-emerald-700' : 'text-slate-700'}`}>
                        {student.firstName} {student.lastName}
                      </span>
                    </div>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${presentIds.has(student.id) ? 'text-emerald-600' : 'text-slate-300'}`}>
                      {presentIds.has(student.id) ? t('students.att.present') : t('students.att.absent')}
                    </span>
                  </div>
                ))}
              </div>

              <div className="space-y-4 pt-6 border-t border-slate-50">
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">{t('students.att.notes')}</label>
                <textarea 
                  value={attNotes}
                  onChange={(e) => setAttNotes(e.target.value)}
                  placeholder={t('students.att.notes_ph')}
                  className="w-full p-6 bg-slate-50 border border-slate-100 rounded-[2rem] outline-none focus:ring-2 focus:ring-indigo-500 h-32 font-medium"
                />
                <button 
                  onClick={saveAttendance}
                  disabled={filteredStudents.length === 0}
                  className={`w-full py-5 rounded-[1.5rem] font-black text-lg transition shadow-xl ${attendanceSaved ? 'bg-emerald-500 text-white' : 'bg-slate-900 text-white hover:bg-slate-800'}`}
                >
                  {attendanceSaved ? t('students.att.saved') : t('students.att.confirm')}
                </button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'HISTORY' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-black text-slate-800">{t('students.hist.title')}</h2>
            <div className="grid grid-cols-1 gap-4">
              {attendanceRecords.length === 0 && (
                <div className="py-20 text-center text-slate-400 bg-white rounded-[2rem] border border-dashed border-slate-200">
                  <p className="font-bold">{t('students.hist.empty')}</p>
                </div>
              )}
              {attendanceRecords.slice().reverse().map(record => {
                const group = groups.find(g => g.id === record.groupId);
                return (
                  <div key={record.id} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-8 group">
                    <div className="flex items-center gap-6 flex-1">
                      <div className="w-16 h-16 bg-slate-50 rounded-2xl flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                        <span className="text-[10px] font-black uppercase">{new Date(record.date).toLocaleString('default', { month: 'short' })}</span>
                        <span className="text-xl font-black">{record.date.split('-')[2]}</span>
                      </div>
                      <div>
                        <div className="flex gap-2 mb-1">
                          <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[9px] font-black uppercase rounded">{group?.name || t('students.hist.group_deleted')}</span>
                          <span className="px-2 py-0.5 bg-emerald-50 text-emerald-600 text-[9px] font-black uppercase rounded">{record.presentStudentIds.length} presentes</span>
                        </div>
                        <h4 className="font-bold text-slate-700 line-clamp-1">{record.sessionNotes || t('students.hist.no_notes')}</h4>
                      </div>
                    </div>
                    <button 
                      onClick={() => setSelectedRecordDetails(record)}
                      className="px-6 py-3 bg-slate-50 text-slate-400 rounded-xl font-black text-xs uppercase hover:bg-indigo-50 hover:text-indigo-600 transition tracking-widest">
                      {t('students.hist.details')}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* MODAL DETALLE DE SESIÓN */}
      {selectedRecordDetails && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-2xl shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center shrink-0">
               <div>
                 <div className="text-[10px] font-black uppercase tracking-widest text-indigo-600 mb-1">Detalle de Asistencia</div>
                 <h3 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                   <Calendar className="text-slate-400" size={24} /> 
                   {new Date(selectedRecordDetails.date).toLocaleDateString(undefined, { dateStyle: 'long' })}
                 </h3>
               </div>
               <button onClick={() => setSelectedRecordDetails(null)} className="p-3 hover:bg-rose-50 hover:text-rose-500 rounded-full transition"><X size={24} /></button>
            </div>
            <div className="p-8 overflow-y-auto space-y-8">
               <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                  <div className="flex items-center gap-2 text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest">
                    <FileText size={14} /> Notas de la sesión
                  </div>
                  <p className="text-slate-700 font-medium italic">
                    {selectedRecordDetails.sessionNotes || "Sin notas registradas."}
                  </p>
               </div>

               <div className="space-y-4">
                  <div className="flex justify-between items-end px-2">
                    <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Lista de Alumnos</h4>
                    <span className="text-xs font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full">
                      {selectedRecordDetails.presentStudentIds.length} Presentes
                    </span>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {students.filter(s => s.groupId === selectedRecordDetails.groupId).map(student => {
                      const isPresent = selectedRecordDetails.presentStudentIds.includes(student.id);
                      return (
                        <div key={student.id} className={`flex items-center gap-3 p-4 rounded-2xl border transition-all ${isPresent ? 'bg-emerald-50 border-emerald-100 text-emerald-700' : 'bg-slate-50 border-slate-100 text-slate-400 opacity-60'}`}>
                          {isPresent ? <UserCheck size={18} /> : <UserX size={18} />}
                          <span className="font-bold">{student.firstName} {student.lastName}</span>
                        </div>
                      );
                    })}
                  </div>
               </div>
            </div>
          </div>
        </div>
