    firstName: '', lastName: '', age: 0, position: '', groupId: '', emergencyContact: '', active: true
  });

  const [groupForm, setGroupForm] = useState<Partial<Group>>({
    name: '', description: '', level: DifficultyLevel.ALL_AGES
  });

  const [attendanceDate, setAttendanceDate] = useState(new Date().toISOString().split('T')[0]);
  const [presentIds, setPresentIds] = useState<Set<string>>(new Set());
  const [attNotes, setAttNotes] = useState('');
  const [attendanceSaved, setAttendanceSaved] = useState(false);

  // Validación de si ya se pasó lista hoy
  const alreadyTakenRecord = attendanceRecords.find(
    r => r.groupId === selectedGroupId && r.date === attendanceDate
  );

  useEffect(() => {
    loadAllData();
  }, []);

  const loadAllData = async () => {
    setLoading(true);
    try {
      const [s, g, a] = await Promise.all([
        storage.getStudents(),
        storage.getGroups(),
        storage.getAttendance()
      ]);
      setStudents(s || []);
      setGroups(g || []);
      setAttendanceRecords(a || []);

      if (g && g.length > 0 && !selectedGroupId) {
        setSelectedGroupId(g[0].id);
      }
    } catch (error) {
      console.error("Error loading data:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateGroup = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!groupForm.name?.trim()) return;

    const newGroup: Group = {
      id: storage.generateId(),
      name: groupForm.name.trim(),
      description: groupForm.description || '',
      level: groupForm.level || DifficultyLevel.ALL_AGES,
      createdAt: new Date().toISOString()
    };

    try {
      await storage.addGroup(newGroup);
      setGroupForm({ name: '', description: '', level: DifficultyLevel.ALL_AGES });
      setShowGroupModal(false);
      loadAllData();
    } catch (error) {
      alert("Error saving group.");
    }
  };

  const handleRegisterStudent = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!studentForm.firstName || !studentForm.groupId) return;
    const newStudent: Student = {
      ...studentForm as Student,
      id: storage.generateId(),
      active: true
    };
    await storage.addStudent(newStudent);
    setShowStudentModal(false);
    loadAllData();
  };

  const saveAttendance = async () => {
    if (!selectedGroupId || alreadyTakenRecord) return;

    const record: AttendanceRecord = {
      id: storage.generateId(),
      date: attendanceDate,
      groupId: selectedGroupId,
      presentStudentIds: Array.from(presentIds),
      sessionNotes: attNotes
    };

    try {
      await storage.saveAttendance(record);
      setAttendanceSaved(true);
      setTimeout(() => setAttendanceSaved(false), 3000);
      loadAllData();
    } catch (error) {
      console.error("Error saving attendance:", error);
    }
  };

  const toggleAttendance = (studentId: string) => {
    if (alreadyTakenRecord) return; // No permitir cambios si ya existe el registro final
    const newPresentIds = new Set(presentIds);
    if (newPresentIds.has(studentId)) {
      newPresentIds.delete(studentId);
    } else {
      newPresentIds.add(studentId);
    }
    setPresentIds(newPresentIds);
  };

  const filteredStudents = students.filter(s => 
    s.groupId === selectedGroupId && 
    (s.firstName.toLowerCase().includes(searchTerm.toLowerCase()) || 
     s.lastName.toLowerCase().includes(searchTerm.toLowerCase()))
  );

  if (loading && groups.length === 0) {
    return <div className="p-10 text-center text-slate-400 font-bold animate-pulse">{t('common.loading')}</div>;
  }

  return (
    <div className="space-y-6 animate-fade-in pb-20">
      {/* Sub Nav */}
      <div className="flex bg-white p-1 rounded-2xl shadow-sm border border-slate-200 overflow-x-auto">
        {(['GROUPS', 'LIST', 'ATTENDANCE', 'HISTORY'] as const).map(tab => (
          <button
            key={tab}
            onClick={() => setActiveTab(tab)}
            className={`flex-1 min-w-max px-4 py-3 rounded-xl flex items-center justify-center gap-2 font-black transition ${activeTab === tab ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-500 hover:bg-slate-50'}`}
          >
            {tab === 'GROUPS' && <Layers size={18} />}
            {tab === 'LIST' && <Users size={18} />}
            {tab === 'ATTENDANCE' && <ClipboardCheck size={18} />}
            {tab === 'HISTORY' && <History size={18} />}
            {t(`students.${tab.toLowerCase()}`)}
          </button>
        ))}
      </div>

      <div className="min-h-[500px]">
        {activeTab === 'GROUPS' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div>
                <h2 className="text-2xl font-black text-slate-800">{t('groups.title')}</h2>
                <p className="text-slate-500 font-medium">{t('groups.subtitle')}</p>
              </div>
              <button onClick={() => setShowGroupModal(true)} className="bg-indigo-600 text-white px-6 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-indigo-700 transition shadow-lg shadow-indigo-100">
                <FolderPlus size={18} /> {t('groups.new')}
              </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
              {groups.map(group => (
                <button
                  key={group.id}
                  onClick={() => { setSelectedGroupId(group.id); setActiveTab('LIST'); }}
                  className={`p-8 rounded-[2.5rem] border text-left transition-all duration-300 group ${selectedGroupId === group.id ? 'bg-slate-900 border-slate-900 text-white shadow-2xl' : 'bg-white border-slate-100 hover:border-indigo-200 shadow-sm'}`}
                >
                  <div className="flex justify-between items-start mb-6">
                    <div className={`p-4 rounded-2xl transition-colors ${selectedGroupId === group.id ? 'bg-indigo-500/20 text-white' : 'bg-indigo-50 text-indigo-600'}`}>
                      <Users size={24} />
                    </div>
                    <span className={`text-[10px] font-black uppercase px-3 py-1.5 rounded-full ${selectedGroupId === group.id ? 'bg-white/10 text-white' : 'bg-slate-100 text-slate-500'}`}>
                      {t(`diff.${group.level}`)}
                    </span>
                  </div>
                  <h3 className="text-xl font-black mb-2">{group.name}</h3>
                  <p className={`text-sm line-clamp-2 font-medium ${selectedGroupId === group.id ? 'text-slate-400' : 'text-slate-500'}`}>{group.description}</p>

                  <div className="mt-8 flex items-center gap-2 text-[10px] font-black uppercase tracking-widest opacity-60">
                    <ChevronRight size={14} /> Ver equipo
                  </div>
                </button>
              ))}
            </div>
          </div>
        )}

        {activeTab === 'LIST' && (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
              <div className="flex items-center gap-4">
                <select 
                  value={selectedGroupId} 
                  onChange={(e) => setSelectedGroupId(e.target.value)}
                  className="bg-white border border-slate-200 px-4 py-3 rounded-xl font-bold text-slate-700 outline-none focus:ring-2 focus:ring-indigo-500"
                >
                  {groups.map(g => <option key={g.id} value={g.id}>{g.name}</option>)}
                </select>
                <h2 className="text-2xl font-black text-slate-800">{t('students.list')}</h2>
              </div>
              <div className="flex items-center gap-2">
                <div className="relative">
                  <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                  <input 
                    type="text" 
                    placeholder={t('groups.search_ph')}
                    value={searchTerm}
                    onChange={(e) => setSearchTerm(e.target.value)}
                    className="pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-medium text-sm"
                  />
                </div>
                <button onClick={() => setShowStudentModal(true)} className="bg-slate-900 text-white px-5 py-3 rounded-xl font-black flex items-center gap-2 hover:bg-slate-800 transition">
                  <UserPlus size={18} /> {t('students.new_btn')}
                </button>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] border border-slate-100 shadow-sm overflow-hidden">
              <div className="overflow-x-auto">
                <table className="w-full text-left">
                  <thead>
                    <tr className="bg-slate-50 border-b border-slate-100">
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">{t('students.table.student')}</th>
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">{t('students.table.position')}</th>
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400">{t('students.table.contact')}</th>
                      <th className="px-8 py-5 text-[10px] font-black uppercase tracking-widest text-slate-400 text-right">{t('students.table.actions')}</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-slate-50">
                    {filteredStudents.length === 0 && (
                      <tr>
                        <td colSpan={4} className="px-8 py-20 text-center text-slate-400 font-bold">
                          {t('students.table.empty')}
                        </td>
                      </tr>
                    )}
                    {filteredStudents.map(student => (
                      <tr key={student.id} className="hover:bg-slate-50 transition-colors group">
                        <td className="px-8 py-5">
                          <div className="flex items-center gap-3">
                            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center font-black">
                              {student.firstName[0]}{student.lastName[0]}
                            </div>
                            <div>
                              <div className="font-bold text-slate-800">{student.firstName} {student.lastName}</div>
                              <div className="text-[10px] text-slate-400 font-black uppercase">{student.age} {t('modal.student.age')}</div>
                            </div>
                          </div>
                        </td>
                        <td className="px-8 py-5">
                          <span className="px-3 py-1 bg-slate-100 text-slate-600 rounded-lg text-xs font-bold uppercase tracking-wider">{student.position}</span>
                        </td>
                        <td className="px-8 py-5">
                          <div className="text-sm font-medium text-slate-600">{student.emergencyContact}</div>
                        </td>
                        <td className="px-8 py-5 text-right">
                          <div className="flex items-center justify-end gap-2">
                             <button onClick={() => setSelectedStudentHistory(student)} className="p-2 text-slate-300 hover:text-indigo-600 transition-colors">
                               <Clock size={18} />
                             </button>
                             <button onClick={() => storage.removeStudent(student.id).then(loadAllData)} className="p-2 text-slate-300 hover:text-rose-500 transition-colors">
                               <Trash2 size={18} />
                             </button>
                          </div>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'ATTENDANCE' && (
          <div className="space-y-6 max-w-4xl mx-auto">
            <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-8">
              <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div>
                  <h2 className="text-2xl font-black text-slate-800">{t('students.att.title')}</h2>
                  <p className="text-slate-500 font-medium">{t('students.att.desc')}</p>
                </div>
                <input 
                  type="date" 
                  value={attendanceDate}
                  onChange={(e) => setAttendanceDate(e.target.value)}
                  className="px-4 py-3 bg-slate-50 border border-slate-100 rounded-xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold text-indigo-600"
                />
              </div>

              {alreadyTakenRecord ? (
                <div className="bg-amber-50 border border-amber-100 p-6 rounded-3xl flex items-center gap-4 text-amber-700 animate-fade-in">
                  <AlertCircle className="shrink-0" />
                  <div>
                    <p className="font-black text-sm uppercase tracking-widest">Atención: Lista ya registrada</p>
                    <p className="text-sm font-medium">Ya has pasado lista para este grupo en la fecha seleccionada. Puedes consultarla en el Historial.</p>
                  </div>
                  <button 
                    onClick={() => { setSelectedRecordDetails(alreadyTakenRecord) }}
                    className="ml-auto px-4 py-2 bg-amber-200 text-amber-900 rounded-xl text-xs font-black uppercase tracking-widest"
                  >
                    Ver Registro
                  </button>
                </div>
              ) : null}

              <div className={`space-y-4 ${alreadyTakenRecord ? 'opacity-40 pointer-events-none grayscale' : ''}`}>
                {filteredStudents.length === 0 && (
                  <div className="py-12 text-center text-slate-400 font-bold bg-slate-50 rounded-3xl border border-dashed border-slate-200">
                    {t('students.att.no_students')}
                  </div>
                )}
                {filteredStudents.map(student => (
                  <div 
                    key={student.id} 
                    onClick={() => toggleAttendance(student.id)}
                    className={`flex items-center justify-between p-4 rounded-2xl border cursor-pointer transition-all ${presentIds.has(student.id) ? 'bg-emerald-50 border-emerald-100' : 'bg-white border-slate-100'}`}
                  >
                    <div className="flex items-center gap-4">
                      <div className={`w-6 h-6 rounded-lg border-2 flex items-center justify-center transition-colors ${presentIds.has(student.id) ? 'bg-emerald-500 border-emerald-500 text-white' : 'border-slate-200'}`}>
                        {presentIds.has(student.id) && <CheckCircle size={14} />}
                      </div>
                      <span className={`font-bold ${presentIds.has(student.id) ? 'text-emerald-700' : 'text-slate-700'}`}>
                        {student.firstName} {student.lastName}
                      </span>
                    </div>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${presentIds.has(student.id) ? 'text-emerald-600' : 'text-slate-300'}`}>
                      {presentIds.has(student.id) ? t('students.att.present') : t('students.att.absent')}
                    </span>
                  </div>
                ))}
              </div>

              <div className={`space-y-4 pt-6 border-t border-slate-50 ${alreadyTakenRecord ? 'hidden' : ''}`}>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">{t('students.att.notes')}</label>
                <textarea 
                  value={attNotes}
                  onChange={(e) => setAttNotes(e.target.value)}
                  placeholder={t('students.att.notes_ph')}
                  className="w-full p-6 bg-slate-50 border border-slate-100 rounded-[2rem] outline-none focus:ring-2 focus:ring-indigo-500 h-32 font-medium"
                />
                <button 
                  onClick={saveAttendance}
                  disabled={filteredStudents.length === 0 || !!alreadyTakenRecord}
                  className={`w-full py-5 rounded-[1.5rem] font-black text-lg transition shadow-xl ${attendanceSaved ? 'bg-emerald-500 text-white' : 'bg-slate-900 text-white hover:bg-slate-800 disabled:opacity-50'}`}
                >
                  {attendanceSaved ? t('students.att.saved') : t('students.att.confirm')}
                </button>
              </div>
            </div>
          </div>
        )}

        {activeTab === 'HISTORY' && (
          <div className="space-y-6">
            <h2 className="text-2xl font-black text-slate-800">{t('students.hist.title')}</h2>
            <div className="grid grid-cols-1 gap-4">
              {attendanceRecords.length === 0 && (
                <div className="py-20 text-center text-slate-400 bg-white rounded-[2rem] border border-dashed border-slate-200">
                  <p className="font-bold">{t('students.hist.empty')}</p>
                </div>
              )}
              {attendanceRecords.slice().reverse().map(record => {
                const group = groups.find(g => g.id === record.groupId);
                return (
                  <div key={record.id} className="bg-white p-8 rounded-[2rem] border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-8 group">
                    <div className="flex items-center gap-6 flex-1">
                      <div className="w-16 h-16 bg-slate-50 rounded-2xl flex flex-col items-center justify-center border border-slate-100 group-hover:bg-indigo-600 group-hover:text-white transition-colors">
                        <span className="text-[10px] font-black uppercase">{new Date(record.date).toLocaleString('default', { month: 'short' })}</span>
                        <span className="text-xl font-black">{record.date.split('-')[2]}</span>
                      </div>
                      <div>
                        <div className="flex gap-2 mb-1">
                          <span className="px-2 py-0.5 bg-indigo-50 text-indigo-600 text-[9px] font-black uppercase rounded">{group?.name || t('students.hist.group_deleted')}</span>
                          <span className="px-2 py-0.5 bg-emerald-50 text-emerald-600 text-[9px] font-black uppercase rounded">{record.presentStudentIds.length} presentes</span>
                        </div>
                        <h4 className="font-bold text-slate-700 line-clamp-1">{record.sessionNotes || t('students.hist.no_notes')}</h4>
                      </div>
                    </div>
                    <button 
                      onClick={() => setSelectedRecordDetails(record)}
                      className="px-6 py-3 bg-slate-50 text-slate-400 rounded-xl font-black text-xs uppercase hover:bg-indigo-50 hover:text-indigo-600 transition tracking-widest">
                      {t('students.hist.details')}
                    </button>
                  </div>
                );
              })}
            </div>
          </div>
        )}
      </div>

      {/* MODAL DETALLE DE SESIÓN */}
      {selectedRecordDetails && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-2xl shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center shrink-0">
               <div>
                 <div className="text-[10px] font-black uppercase tracking-widest text-indigo-600 mb-1">Detalle de Asistencia</div>
                 <h3 className="text-2xl font-black text-slate-900 flex items-center gap-3">
                   <Calendar className="text-slate-400" size={24} /> 
                   {new Date(selectedRecordDetails.date).toLocaleDateString(undefined, { dateStyle: 'long' })}
                 </h3>
               </div>
               <button onClick={() => setSelectedRecordDetails(null)} className="p-3 hover:bg-rose-50 hover:text-rose-500 rounded-full transition"><X size={24} /></button>
            </div>
            <div className="p-8 overflow-y-auto space-y-8">
               <div className="bg-slate-50 p-6 rounded-[2rem] border border-slate-100">
                  <div className="flex items-center gap-2 text-[10px] font-black uppercase text-slate-400 mb-3 tracking-widest">
                    <FileText size={14} /> Notas de la sesión
                  </div>
                  <p className="text-slate-700 font-medium italic">
                    {selectedRecordDetails.sessionNotes || "Sin notas registradas."}
                  </p>
               </div>

               <div className="space-y-4">
                  <div className="flex justify-between items-end px-2">
                    <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Lista de Alumnos</h4>
                    <span className="text-xs font-black text-emerald-600 bg-emerald-50 px-3 py-1 rounded-full">
                      {selectedRecordDetails.presentStudentIds.length} Presentes
                    </span>
                  </div>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
                    {students.filter(s => s.groupId === selectedRecordDetails.groupId).map(student => {
                      const isPresent = selectedRecordDetails.presentStudentIds.includes(student.id);
                      return (
                        <div key={student.id} className={`flex items-center gap-3 p-4 rounded-2xl border transition-all ${isPresent ? 'bg-emerald-50 border-emerald-100 text-emerald-700' : 'bg-slate-50 border-slate-100 text-slate-400 opacity-60'}`}>
                          {isPresent ? <UserCheck size={18} /> : <UserX size={18} />}
                          <span className="font-bold">{student.firstName} {student.lastName}</span>
                        </div>
                      );
                    })}
                  </div>
               </div>
            </div>
          </div>
        </div>
      )}

      {/* MODAL HISTORIAL INDIVIDUAL ALUMNO */}
      {selectedStudentHistory && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[200] flex items-center justify-center p-4">
          <div className="bg-white rounded-[3rem] w-full max-w-2xl shadow-2xl animate-scale-in max-h-[90vh] flex flex-col">
            <div className="p-10 bg-slate-900 text-white rounded-t-[3rem] shrink-0">
               <div className="flex justify-between items-start">
                  <div className="flex items-center gap-5">
                    <div className="w-16 h-16 bg-indigo-600 rounded-2xl flex items-center justify-center text-2xl font-black">
                      {selectedStudentHistory.firstName[0]}{selectedStudentHistory.lastName[0]}
                    </div>
                    <div>
                      <h3 className="text-3xl font-black tracking-tighter">{selectedStudentHistory.firstName} {selectedStudentHistory.lastName}</h3>
                      <p className="text-indigo-400 font-bold uppercase text-[10px] tracking-widest">{selectedStudentHistory.position} • {selectedStudentHistory.age} años</p>
                    </div>
                  </div>
                  <button onClick={() => setSelectedStudentHistory(null)} className="p-3 bg-white/10 rounded-full hover:bg-rose-500 transition"><X size={24} /></button>
               </div>
            </div>
            <div className="p-10 overflow-y-auto space-y-6">
               <h4 className="text-[10px] font-black uppercase text-slate-400 tracking-widest">Registro de Asistencia Reciente</h4>
               <div className="space-y-3">
                 {attendanceRecords
                   .filter(r => r.groupId === selectedStudentHistory.groupId)
                   .slice().reverse()
                   .map(record => {
                     const isPresent = record.presentStudentIds.includes(selectedStudentHistory.id);
                     return (
                       <div key={record.id} className="flex items-center justify-between p-6 bg-white border border-slate-100 rounded-[2rem] shadow-sm">
                         <div className="flex items-center gap-4">
                            <div className="bg-slate-50 p-3 rounded-2xl border border-slate-100">
                               <Calendar size={18} className="text-slate-400" />
                            </div>
                            <div>
                               <div className="font-black text-slate-800">{new Date(record.date).toLocaleDateString()}</div>
                               <div className="text-[10px] text-slate-400 font-bold uppercase line-clamp-1">{record.sessionNotes || "Sin notas"}</div>
                            </div>
                         </div>
                         <div className={`flex items-center gap-2 px-4 py-2 rounded-full font-black text-[10px] uppercase tracking-widest ${isPresent ? 'bg-emerald-100 text-emerald-700' : 'bg-rose-100 text-rose-700'}`}>
                            {isPresent ? <CheckCircle size={14} /> : <X size={14} />}
                            {isPresent ? "Presente" : "Ausente"}
                         </div>
                       </div>
                     );
                 })}
                 {attendanceRecords.filter(r => r.groupId === selectedStudentHistory.groupId).length === 0 && (
                    <div className="py-20 text-center text-slate-400 font-bold italic">
                      Este alumno aún no tiene registros de asistencia.
                    </div>
                 )}
               </div>
            </div>
          </div>
        </div>
      )}

      {/* Group Modal */}
      {showGroupModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg shadow-2xl animate-scale-in">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center">
              <h3 className="text-xl font-black text-slate-900">{t('modal.group.title')}</h3>
              <button onClick={() => setShowGroupModal(false)} className="p-2 hover:bg-rose-50 hover:text-rose-500 rounded-full transition"><X size={20} /></button>
            </div>
            <form onSubmit={handleCreateGroup} className="p-8 space-y-6">
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">{t('modal.group.name')}</label>
                <input required className="w-full p-4 bg-slate-50 border border-slate-100 rounded-2xl outline-none focus:ring-2 focus:ring-indigo-500 font-bold" value={groupForm.name} onChange={e => setGroupForm({ ...groupForm, name: e.target.value })} />
              </div>
              <div>
                <label className="text-[10px] font-black uppercase text-slate-400 ml-1">{t('modal.group.level')}</label>
