                setCurrentView(item.id as ViewState);
                setMobileMenuOpen(false);
              }}
              className={`w-full flex items-center gap-4 px-6 py-4 rounded-[1.5rem] transition-all duration-300 group
                ${currentView === item.id 
                  ? 'bg-slate-900 text-white shadow-2xl shadow-slate-200' 
                  : (item.special ? 'bg-indigo-50 text-indigo-600 hover:bg-indigo-100' : 'hover:bg-slate-50 text-slate-400 hover:text-slate-900')
                }`}
            >
              <div className={`p-2 rounded-xl transition-colors ${currentView === item.id ? 'bg-indigo-500/20 text-white' : (item.special ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-50 text-slate-400 group-hover:bg-white group-hover:text-indigo-600')}`}>
                {item.icon}
              </div>
              <span className="font-black text-sm tracking-tight flex-1 text-left">{item.label}</span>
              {item.special && !isPremium && <Lock size={12} className="text-indigo-300" />}
            </button>
          ))}
        </nav>

        <div className="absolute bottom-0 w-full p-8 hidden md:block">
          <div className={`rounded-[2rem] p-6 border transition-all duration-500
            ${isPremium 
              ? 'bg-gradient-to-br from-indigo-600 to-purple-600 text-white border-indigo-400' 
              : 'bg-slate-900 text-white border-slate-800'}`}>
            <div className="flex items-center justify-between mb-2">
               <h4 className={`font-black text-xs uppercase tracking-widest ${isPremium ? 'text-white' : 'text-indigo-400'}`}>
                 {isPremium ? 'PRO MEMBER' : 'FREE PLAN'}
