               {isPremium && <ShieldCheck size={16} />}
            </div>
            <p className="text-[10px] text-slate-300 font-bold mb-3">
              {isPremium ? 'Todos los servicios activos.' : 'Pásate a Pro para IA ilimitada.'}
            </p>
            {!isPremium && (
               <button 
                 onClick={() => { setCurrentView('AI_COACH'); setMobileMenuOpen(false); }}
                 className="w-full bg-indigo-600 py-2 rounded-xl text-[10px] font-black hover:bg-indigo-500 transition"
               >
                  UPGRADE NOW
               </button>
            )}
          </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-1 overflow-y-auto h-screen scroll-smooth bg-slate-50/50">
        <div className="max-w-6xl mx-auto p-6 md:p-12">
          <header className="mb-10 flex justify-between items-end">
            <div>
              <div className="text-[10px] font-black text-indigo-600 uppercase tracking-[0.3em] mb-2">Coach Dashboard</div>
              <h2 className="text-5xl font-black text-slate-900 tracking-tighter">
