export const getWalletTransactions = async (studentId?: string): Promise<WalletTransaction[]> => {
  const all = getLocalData<WalletTransaction>('wallet');
  if (studentId) return all.filter(t => t.studentId === studentId);
  return all;
};

export const addWalletTransaction = async (tx: WalletTransaction): Promise<void> => {
  const txs = getLocalData<WalletTransaction>('wallet');
  saveLocalData('wallet', [...txs, tx]);
};

