                <p className="text-slate-500 font-medium">{t('groups.subtitle')}</p>
              </div>
              <button onClick={() => setShowGroupModal(true)} className="bg-emerald-600 text-white px-6 py-3 rounded-2xl font-black flex items-center gap-2 hover:bg-emerald-700 transition shadow-lg shadow-emerald-100">
                <FolderPlus size={18} /> {t('groups.new')}
              </button>
